INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"animated-letters"', '"animation"', '"vanilla"', '{"demo.css": "@keyframes breath {\n  from {\n    animation-timing-function: ease-out;\n  }\n\n  to {\n    transform: scale(1.25) translateY(-5px) perspective(1px);\n    text-shadow: 0 0 40px var(--glow-color);\n    animation-timing-function: ease-in-out;\n  }\n}\n\n@media (prefers-reduced-motion:no-preference) {\n  [letter-animation] > span {\n    display: inline-block;\n    white-space: break-spaces;\n  }\n\n  [letter-animation=breath] {\n    --glow-color: white;\n  }\n\n  [letter-animation=breath]>span {\n    animation: breath 1.2s ease calc(var(--index) * 100 * 1ms) infinite alternate;\n  }\n}\n\n@media (prefers-reduced-motion:no-preference) and (prefers-color-scheme: light) {\n  [letter-animation=breath] {\n    --glow-color: black;\n  }\n}", "demo.html": "<h1 split-by=\"letter\" letter-animation=\"breath\">\n  animated letters\n</h1>\n", "demo.js": "const span = (text, index) => {\n  const node = document.createElement(''span'')\n\n  node.textContent = text\n  node.style.setProperty(''--index'', index)\n  \n  return node\n}\n\nconst byLetter = text =>\n  [...text].map(span)\n\nconst {matches:motionOK} = window.matchMedia(\n  ''(prefers-reduced-motion: no-preference)''\n)\n\nif (motionOK) {\n  const splitTargets = document.querySelectorAll(''[split-by]'')\n\n  splitTargets.forEach(node => {\n    let nodes = byLetter(node.innerText)\n\n    if (nodes)\n      node.firstChild.replaceWith(...nodes)\n  })\n}"}', '{}', '{"original_path": "patterns/animation/animated-letters"}'), ('"animated-words"', '"animation"', '"vanilla"', '{"demo.css": "@keyframes trampoline {\n  0% {\n    transform: translateY(100%);\n    animation-timing-function: ease-out\n  }\n\n  50% {\n    transform: translateY(0);\n    animation-timing-function: ease-in\n  }\n}\n\n@media (prefers-reduced-motion:no-preference) {\n  [word-animation] {\n    display: inline-f