.forEach(node => {\n    let nodes = byLetter(node.innerText)\n\n    if (nodes)\n      node.firstChild.replaceWith(...nodes)\n  })\n}"}', '{}', '{"original_path": "patterns/animation/interactive-letters"}'), ('"interactive-words"', '"animation"', '"vanilla"', '{"demo.css": "@media (prefers-reduced-motion:no-preference) {\n  [word-animation] {\n    display: inline-flex;\n    flex-wrap: wrap;\n    gap: 1ch\n  }\n}\n\n@media (prefers-reduced-motion:no-preference) and (hover) {\n  [word-animation=hover] {\n    overflow: hidden;\n    overflow: clip\n  }\n\n  [word-animation=hover]>span {\n    transition: transform .3s ease;\n    cursor: pointer\n  }\n\n  [word-animation=hover]>span:not(:hover) {\n    transform: translateY(50%)\n  }\n}", "demo.html": "<h1 split-by=\"word\" word-animation=\"hover\">\n  hover the words\n</h1>", "demo.js": "const span = (text, index) => {\n  const node = document.createElement(''span'')\n\n  node.textContent = text\n  node.style.setProperty(''--index'', index)\n  \n  return node\n}\n\nexport const byWord = text =>\n  text.split('' '').map(span)\n\nconst {matches:motionOK} = window.matchMedia(\n  ''(prefers-reduced-motion: no-preference)''\n)\n\nif (motionOK) {\n  const splitTargets = document.querySelectorAll(''[split-by]'')\n\n  splitTargets.forEach(node => {\n    let nodes = byWord(node.innerText)\n\n    if (nodes)\n      node.firstChild.replaceWith(...nodes)\n  })\n}"}', '{}', '{"original_path": "patterns/animation/interactive-words"}'), ('"copy-images"', '"clipboard"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n}\n\nhtml {\n  box-sizing: border-box;\n}\n\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\n\nbody {\n  margin: 1rem;\n  font-family: system-ui, sans-serif;\n}\n\nbutton {\n  display: block;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link\n      rel=\"icon\"\n      href=\"data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22><text y=%22.9em%22 font-size=%2290%22>\ud83c\udf89</text></svg>\"\n    />\n    <title>How to copy images</title>\n  </head>\n  <body>\n    <h1>How to copy images</h1>\n    <img src=\"assets/fugu.svg\" alt=\"Fugu fish.\" width=\"128\" height=\"128\">\n    <button type=\"button\">Copy</button>\n  </body>\n</html>\n", "demo.js": "const button = document.querySelector(''button'');\nconst img = document.querySelector(''img'');\n\nbutton.addEventListener(''click'', async () => {\n  const responsePromise = fetch(img.src);\n\n  try {\n    if (''write'' in navigator.clipboard) {\n      await navigator.clipboard.write([\n        new ClipboardItem({\n          ''image/svg+xml'': new Promise(async (resolve) => {\n            const blob = await responsePromise.then(response => response.blob());\n            resolve(blob);\n          }),\n        }),\n      ]);\n      // Image copied as image.\n    } else {\n      const text = await responsePromise.then(response => response.text());\n      await navigator.clipboard.writeText(text);\n      // Image copied as source code.\n    }\n  } catch (err) {\n    console.error(err.name, err.message);\n  }\n});\n", "demo.png": "\ufffdPNG\r\n\u001a\n\u0000\u0000\u0000\rIHDR\u0000\u0000\u0002\u0000\u0000\u0000\u0002\u0000\b\u0006\u0000\u0000\u0000\ufffdx\ufffd\ufffd\u0000\u0000\u0000\tpHYs\u0000\u0000;\u000e\u0000\u0000;\u000e\u0001\u0336\ufffd\ufffd\u0000\u0000\u0000\u0019tEXtSoftware\u0000www.inkscape.org\ufffd\ufffd<\u001a\u0000\u0000 \u0000IDATx\ufffd\ufffd\ufffdw|\u001c\u05797\ufffd\ufffd3e\ufffd\ufffde[\ufffd\u0018Y\ufffd-\ufffd\u0606\u0018\f\u0004[\ufffd\ufffd\ufffd\u000b.\ufffd\ufffd\ufffd\\\u0002$\ufffd\ufffdp\u0013\ufffd\ufffd\u0710\ufffd:\ufffd\ufffd\ufffdBH\ufffd\ufffd\ufffd`R\b\ufffd@\b\u0018C \t-!\u0010 \u0006Ls\ufffde\ufffd\u0576\ufffd9\ufffd\ufffd\ufffdJ\ufffd\ufffdvgf\ufffd\ufffd\u76cf\ufffd%\u035cyv\ufffd\ufffd\ufffd\ufffd)\ufffd\u