5h-192v192h192v-192z\"/></g></g><g fill=\"#F44336\"><rect width=\"4\" height=\"128\" opacity=\".3\"/><rect x=\"124\" width=\"4\" height=\"128\" opacity=\".3\"/><rect transform=\"matrix(-1.837e-16 1 -1 -1.837e-16 66 -62)\" x=\"62\" y=\"-58\" width=\"4\" height=\"120\" opacity=\".3\"/><rect transform=\"matrix(-1.837e-16 1 -1 -1.837e-16 190 62)\" x=\"62\" y=\"66\" width=\"4\" height=\"120\" opacity=\".3\"/></g></g></g></svg>\n"}', '{}', '{"original_path": "patterns/clipboard/copy-images"}'), ('"copy-text"', '"clipboard"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n}\n\nhtml {\n  box-sizing: border-box;\n}\n\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\n\nbody {\n  margin: 1rem;\n  font-family: system-ui, sans-serif;\n}\n\nbutton {\n  display: block;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link\n      rel=\"icon\"\n      href=\"data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22><text y=%22.9em%22 font-size=%2290%22>\ud83c\udf89</text></svg>\"\n    />\n    <title>How to copy text</title>\n  </head>\n  <body>\n    <h1>How to copy text</h1>\n    <textarea rows=\"3\">\nSome sample text for you to copy. Feel free to edit this.</textarea\n    >\n    <button type=\"button\">Copy</button>\n  </body>\n</html>\n", "demo.js": "const textarea = document.querySelector(''textarea'');\nconst button = document.querySelector(''button'');\n\nbutton.addEventListener(''click'', async () => {\n  try {\n    await navigator.clipboard.writeText(textarea.value);\n  } catch (err) {\n    console.error(err.name, err.message);\n  }\n});\n"}', '{}', '{"original_path": "patterns/clipboard/copy-text"}'), ('"paste-files"', '"clipboard"', '"vanilla"', '{"demo.css": "html {\n  box-sizing: border-box;\n  font-family: system-ui, sans-serif;\n  color-scheme: dark light;\n}\n\n*, *:before, *:after {\n  box-sizing: inherit;\n}\n\nbody {\n  margin: 1rem;\n}\n\nimg {\n  height: auto;\n  max-width: 100%;\n  display: block;\n}\n", "demo.html": "<!DOCTYPE html>\n<html>\n  <head>\n    <title>How to paste files</title>\n  </head>\n  <body>\n    <h1>How to paste files</h1>\n    <p>Hit <kbd>\u2318</kbd> + <kbd>v</kbd> (for macOS) or <kbd>ctrl</kbd> + <kbd>v</kbd>\n      (for other operating systems) to paste image or text file(s) anywhere in this page.\n    </p>\n  </body>\n</html>\n", "demo.js": "document.addEventListener(''paste'', async (e) => {\n  // Prevent the default behavior, so you can code your own logic.\n  e.preventDefault();\n  if (!e.clipboardData.files.length) {\n    return;\n  }\n  // Iterate over all pasted files.\n  Array.from(e.clipboardData.files).forEach(async (file) => {\n    // Add more checks here for MIME types you''re interested in,\n    // such as `application/pdf`, `video/mp4`, etc.\n    if (file.type.startsWith(''image/'')) {\n      // For images, create an image and append it to the `body`.\n      const img = document.createElement(''img'');\n      const blob = URL.createObjectURL(file);\n      img.src = blob;\n      document.body.append(img);\n    } else if (file.type.startsWith(''text/'')) {\n      // For text files, read the contents and output it into a `textarea`.\n      const textarea = document.createElement(''textarea'');\n      textarea.value = await file.text();\n      document.body.append(textarea);\n    }\n  });\n});\n"}', '{}', '{"original_path": "patterns/clipboard/paste-files"}'), ('"paste-images"', '"clipboard"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n}\n\nhtml {\n  box-sizing: border-box;\n}\n\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\n\nbody {\n  margin: 1rem;\n  font-family: system-ui, sans-serif;\n}\n\nbutton {\n  display: block;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link\n      rel=\"icon\"\n      href=\"data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22><text y=%22.9em%22 font-size=%2290%22>\ud83c\udf89</text></svg>\"\n    />\n    <title>How to paste images</title>\n  </head>\n  <body>\n    <h1>How to paste images</h1>\n    <p>Hit <kbd>\u2318</kbd> + <kbd>v</kbd> (for macOS) or <kbd>ctrl</kbd> + <kbd>v</kbd>\n      (for other operating systems) to paste images anywhere in this page.\n    </p>\n  </body>\n</html>\n", "demo.js": "document.addEventListener(''paste'', async (e) => {\n  e.preventDefault();\n  const clipboardItems = typeof navigator?.clipboard?.read === ''function'' ? await navigator.clipboard.read() : e.clipboardData.files;\n\n  for (const clipboardItem of clipboardItems) {\n    let blob;\n    if (clipboardItem.type?.startsWith(''image/'')) {\n      // For files from `e.clipboardData.files`.\n      blob = clipboardItem\n      // Do something with the blob.\n      appendImage(blob);\n    } else {\n      // For files from `navigator.clipboard.read()`.\n      const imageTypes = clipboardItem.types?.filter(type => type.startsWith(''image/''))\n      for (const imageType of imageTypes) {\n        blob = await clipboardItem.getType(imageType);\n        // Do something with the blob.\n        appendImage(blob);\n      }\n    }\n  }\n});\n\nconst appendImage = (blob) => {\n  const img = document.createElement(''img'');\n  img.src = URL.createObjectURL(blob);\n  document.body.append(img);\n};"}', '{}', '{"original_path": "patterns/clipboard/paste-images"}'), ('"paste-text"', '"clipboard"', '"vanilla"', '{"demo.css": ":root {\n  color-scheme: dark light;\n}\n\nhtml {\n  box-sizing: border-box;\n}\n\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\n\nbody {\n  margin: 1rem;\n  font-family: system-ui, sans-serif;\n}\n\nbutton {\n  display: block;\n}\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n    <link\n      rel=\"icon\"\n      href=\"data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22><text y=%22.9em%22 font-size=%2290%22>\ud83c\udf89</text></svg>\"\n    />\n    <title>How to paste text</title>\n  </head>\n  <body>\n    <h1>How to paste text</h1>\n    <p>\n      <button type=\"button\">Paste</button>\n    </p>\n    <textarea></textarea>\n  </body>\n</html>\n", "demo.js": "const pasteButton = document.querySelector(''button'');\n\npasteButton.addEventListener(''click'', async () => {\n  try {\n    const text = await navigator.clipboard.readText()\n    document.querySelector(''textarea'').value += text;\n    console.log(''Text pasted.'');\n  } catch (error) {\n    console.log(''Failed to read clipboard. Using execCommand instead.'');\n    document.querySelector(''textarea'').focus();\n    const result = document.execCommand(''paste'')\n    console.log(''document.execCommand result: '', result);\n  }\n});"}', '{}', '{"original_path": "patterns/clipboard/paste-text"}'), ('"breadcrumbs"', '"components"', '"vanilla"', '{"demo.css": ".breadcrumbs {\n  --nav-gap: 2ch;\n\n  display: flex;\n  align-items: center;\n  overflow-x: auto;\n  overscroll-behavior-x: contain;\n  scroll-snap-type: x proximity;\n\n  gap: var(--nav-gap);\n  padding: calc(var(--nav-gap) / 2);\n  scroll-padding-inline: calc(var(--nav-gap) / 2);\n\n  & > a:first-of-type:not(.crumb) {\n    display: inline-flex;\n    align-items: center;\n    gap: calc(var(--nav-gap) / 4);\n\n    @media (width <= 480px) { & > .home-label {\n      display: none;\n    }}\n  }\n\n  & a {\n    text-underline-offset: .25em;\n    outline-offset: 3px;\n\n    /* fix Safari inaccessible dark color scheme links */\n    /* https://bugs.webkit.org/show_bug.cgi?id=226893 */\n    @media (prefers-color-scheme: dark) {\n      @supports (-webkit-hyphens:none) { &[href] {\n        color: hsl(240 100% 81%);\n      }}\n    }\n  }\n\n  & > .crumb:last-of-type {\n    scroll-snap-align: end;\n  }\n\n  @supports (-webkit-hyphens:none) {\n    scroll-snap-type: none;\n  }\n}\n\n.crumb {\n  display: inline-flex;\n  align-items: center;\n  gap: calc(var(--nav-gap) / 4);\n\n  & > a {\n    white-space: nowrap;\n\n    &[aria-current=\"page\"] {\n      font-weight: bold;\n    }\n  }\n\n  &.tree-changed ~ * {\n    display: none;\n  }\n}\n\n.crumb-separator {\n  color: ButtonText;\n}\n\n.disguised-select {\n  inline-size: 100%;\n  block-size: 100%;\n  opacity: .01;\n  font-size: min(100%, 16px);\n}\n\n.crumbicon {\n  --size: 3ch;\n\n  display: grid;\n  grid: [stack] var(--size) / [stack] var(--size);\n  place-items: center;\n  border-radius: 50%;\n\n  --icon-shadow-size: 0px;\n  box-shadow: inset 0 0 0 var(--icon-shadow-size) currentColor;\n  \n  @media (--motionOK) { & {\n    transition: box-shadow .2s ease;\n  }}\n\n  @nest .crumb:is(:focus-within, :hover) > & {\n    --icon-shadow-size: 1px;\n  }\n\n  @nest .crumb > &:is(:focus-within, :hover) {\n    --icon-shadow-size: 2px;\n\n    & svg {\n      stroke-width: 2px;\n    }\n  }\n\n  & > * {\n    grid-area: stack;\n  }\n\n  & > svg {\n    max-block-size: 100%;\n    margin: calc(var(--nav-gap) / 4);\n\n    stroke: currentColor;\n    fill: none;\n    stroke-linecap: round;\n    stroke-linejoin: round;\n    stroke-width: 1px;\n  }\n}", "demo.html": "<nav class=\"breadcrumbs\" role=\"navigation\">\n  <a href=\"./home/\">\n    <span class=\"crumbicon\">\n      <svg viewBox=\"0 0 24 24\" width=\"24\" height=\"24\" aria-hidden=\"true\">\n        <use href=\"#icon-home\" />\n      </svg>\n    </span>\n    <span class=\"home-label\">Home</span>\n  </a>\n\n  <span class=\"crumb-separator\" aria-hidden=\"true\">\u00bb</span>\n\n  <span class=\"crumb\">\n    <a aria-current=\"page\">Page A</a>\n    <span class=\"crumbicon\">\n      <svg viewBox=\"0 0 24 24\" width=\"24\" height=\"24\" aria-hidden=\"true\">\n        <use href=\"#icon-dropdown-arrow\" />\n      </svg>\n      <select class=\"disguised-select\" title=\"Navigate to another page\">\n        <option selected>Page A</option>\n        <option>Page B</option>\n        <option>Page C</option>\n      </select>\n    </span>\n  </span>\n</nav>\n\n<svg style=\"display: none;\">\n\n  <symbol id=\"icon-home\">\n    <title>A home icon</title>\n    <path\n      d=\"M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6\" />\n  </symbol>\n\n  <symbol id=\"icon-dropdown-arrow\">\n    <title>A down arrow</title>\n    <path d=\"M19 9l-7 7-7-7\" />\n  </symbol>\n\n</svg>\n", "demo.js": "const crumbs         = document.querySelectorAll(''.breadcrumbs select'')\nconst allowedKeys    = new Set([''Tab'', ''Enter'', '' ''])\nconst preventedKeys  = new Set([''ArrowUp'', ''ArrowDown''])\n\n// watch crumbs for *full* changes,\n// ensures it''s not a user exploring options via keyboard\ncrumbs.forEach(nav => {\n  let ignoreChange = false\n\n  nav.addEventListener(''change'', e => {\n    if (ignoreChange) return\n\n    const option = e.target\n    const choice = option.value\n    const crumb = option.closest(''.crumb'')\n\n    // flag crumb so adjacent siblings can be hidden\n    crumb.classList.add(''tree-changed'')\n\n    // update crumb text to reflect the user''s choice\n    crumb.querySelector('':scope > a'').textContent = choice\n\n    routePage(choice)\n  })\n\n  nav.addEventListener(''keydown'', ({ key }) => {\n    if (preventedKeys.has(key))\n      ignoreChange = true\n    else if (allowedKeys.has(key))\n      ignoreChange = false\n  })\n})\n\nconst routePage = route => {\n  console.info(''change path to: '', route)\n  // change entire URL (window.location)\n  // or \n  // use your favorite clientside framework''s router\n}"}', '{}', '{"original_path": "patterns/components/breadcrumbs"}'), ('"buttons"', '"components"', '"vanilla"', '{"demo.css": ":where(\n  button,\n  input[type=\"button\"],\n  input[type=\"submit\"],\n  input[type=\"reset\"],\n  input[type=\"file\"]\n),\n:where(input[type=\"file\"])::file-selector-button {\n  --_accent-light: hsl(210 100% 40%);\n  --_accent-dark: hsl(210 50% 70%);\n  --_accent: var(--_accent-light);\n\n  --_text-light: hsl(210 10% 30%);\n  --_text-dark: hsl(210 5% 95%);\n  --_text: var(--_text-light);\n  \n  --_bg-light: hsl(0 0% 100%);\n  --_bg-dark: hsl(210 9% 31%);\n  --_bg: var(--_bg-light);\n\n  --_input-well-light: hsl(210 16% 87%);\n  --_input-well-dark: hsl(204 10% 10%);\n  --_input-well: var(--_input-well-light);\n\n  --_padding-inline: 1.75ch;\n  --_padding-block: .75ch;\n  \n  --_border-radius: .5ch;\n  --_border-light: hsl(210 14% 89%);\n  --_border-dark: var(--_bg-dark);\n  --_border: var(--_border-light);\n  \n  --_highlight-size: 0;\n  --_highlight-light: hsl(210 10% 71% / 25%);\n  --_highlight-dark: hsl(210 10% 5% / 25%);\n  --_highlight: var(--_highlight-light);\n  \n  --_ink-shadow-light: 0 1px 0 var(--_border-light);\n  --_ink-shadow-dark: 0 1px 0 hsl(210 11% 15%);\n  --_ink-shadow: var(--_ink-shadow-light);\n  \n  --_icon-size: 2ch;\n  --_icon-color: var(--_accent);\n\n  --_shadow-color-light: 220 3% 15%;\n  --_shadow-color-dark: 220 40% 2%;\n  --_shadow-color: var(--_shadow-color-light);\n  --_shadow-strength-light: 1%;\n  --_shadow-strength-dark: 25%;\n  --_shadow-strength: var(--_shadow-strength-light);\n  --_shadow-1: 0 1px 2px -1px hsl(var(--_shadow-color)/calc(var(--_shadow-strength) + 9%));\n  --_shadow-2: 0 3px 5px -2px hsl(var(--_shadow-color)/calc(var(--_shadow-strength) + 3%)),0 7px 14px -5px hsl(var(--_shadow-color)/calc(var(--_shadow-strength) + 5%));\n  \n  --_shadow-depth-light: 0 1px var(--_border-light);\n  --_shadow-depth-dark: 0 1px var(--_bg-dark);\n  --_shadow-depth: var(--_shadow-depth-light);\n\n  --_transition-motion-reduce: ;\n  --_transition-motion-ok:\n    box-shadow 145ms ease,\n    outline-offset 145ms ease\n  ;\n  --_transition: var(--_transition-motion-reduce);\n\n  font: inherit;\n  letter-spacing: inherit;\n  line-height: 1.5;\n  border-radius: var(--_border-radius);\n}\n\n@media (prefers-color-scheme: dark) {\n  :where(\n    button,\n    input[type=\"button\"],\n    input[type=\"submit\"],\n    input[type=\"reset\"],\n    input[type=\"file\"]\n  ),\n  :where(input[type=\"file\"])::file-selector-button {\n    --_bg: var(--_bg-dark);\n    --_text: var(--_text-dark);\n    --_border: var(--_border-dark);\n    --_accent: var(--_accent-dark);\n    --_highlight: var(--_highlight-dark);\n    --_input-well: var(--_input-well-dark);\n    --_ink-shadow: var(--_ink-shadow-dark);\n    --_shadow-depth: var(--_shadow-depth-dark);\n    --_shadow-color: var(--_shadow-color-dark);\n    --_shadow-strength: var(--_shadow-strength-dark);\n  }\n}\n\n@media (prefers-reduced-motion: no-preference) {\n  :where(\n    button,\n    input[type=\"button\"],\n    input[type=\"submit\"],\n    input[type=\"reset\"],\n    input[type=\"file\"]\n  ),\n  :where(input[type=\"file\"])::file-selector-button {\n    --_transition: var(--_transition-motion-ok);\n  }\n}\n\n:where(\n  button,\n  input[type=\"button\"],\n  input[type=\"submit\"],\n  input[type=\"reset\"]\n),\n:where(input[type=\"file\"])::file-selector-button {\n  cursor: pointer;\n  touch-action: manipulation;\n\n  font-size: var(--_size, 1rem);\n  background: var(--_bg);\n  color: var(--_text);\n  border: 2px solid var(--_border);\n  box-shadow: \n    var(--_shadow-2),\n    var(--_shadow-depth),\n    0 0 0 var(--_highlight-size) var(--_highlight)\n  ;\n  text-shadow: var(--_ink-shadow);\n  transition: var(--_transition);\n  \n  display: inline-flex;\n  justify-content: center;\n  align-items: center;\n  text-align: center;\n  gap: 1ch;\n  \n  font-weight: 700;\n  padding-block: var(--_padding-block);\n  padding-inline: var(--_padding-inline);\n\n  user-select: none;\n  -webkit-tap-highlight-color: transparent;\n  -webkit-touch-callout: none;\n}\n\n/* icons */\n:where(\n  button,\n  input[type=\"button\"],\n  input[type=\"submit\"],\n  input[type=\"reset\"]\n) > :where(svg, [data-icon]) {\n  block-size: var(--_icon-size);\n  inline-size: var(--_icon-size);\n  stroke: var(--_icon-color);\n  filter: drop-shadow(var(--_ink-shadow));\n\n  flex-shrink: 0;\n  fill: none;\n  stroke-linecap: round;\n  stroke-linejoin: round;\n}\n\n/* focus */\n:where(button, input):where(:not(:active)):focus-visible {\n  outline-offset: 5px;\n}\n\n/* pressing */\n:where(\n  button,\n  input[type=\"button\"],\n  input[type=\"submit\"],\n  input[type=\"reset\"]\n):where(:not(:active):hover) {\n  --_highlight-size: .5rem;\n}\n\n/* disabled */\n:where(\n  button,\n  input[type=\"button\"],\n  input[type=\"submit\"],\n  input[type=\"reset\"]\n)[disabled] {\n  --_bg: none;\n  --_text-light: hsl(210 7% 40%);\n  --_text-dark: hsl(210 11% 71%);\n\n  cursor: not-allowed;\n  box-shadow: var(--_shadow-1);\n}\n\n/* adaptive indigo text */\n:where(\n  [type=\"submit\"], \n  form button:not([type],[disabled])\n) {\n  --_text: var(--_accent);\n} \n\n/* red reset */\n:where([type=\"reset\"]) {\n  --_border-light: hsl(0 100% 83%);\n  --_highlight-light: hsl(0 100% 89% / 20%);\n  --_text-light: hsl(0 80% 50%);\n  --_text-dark: hsl(0 100% 89%);\n}\n\n:where([type=\"reset\"]):focus-visible {\n  outline-color: currentColor;\n}\n\n/* file input */\n:where(input[type=\"file\"]) {\n  inline-size: 100%;\n  max-inline-size: max-content;\n  background-color: var(--_input-well);\n}\n\n:where(input[type=\"button\"]),\n:where(input[type=\"file\"])::file-selector-button {\n  appearance: none;\n}\n\n:where(input[type=\"file\"])::file-selector-button {\n  margin-inline-end: var(--_padding-inline);\n}\n\n/* special dark theme styles */\n@media (prefers-color-scheme: dark) {\n  :where(\n    [type=\"submit\"],\n    [type=\"reset\"],\n    [disabled],\n    form button:not([type=\"button\"])\n  ) {\n    --_bg: var(--_input-well);\n  }\n}", "demo.html": "<section>\n  <h2>9 button types</h2>\n  <p>Unified modern style, visual differences reinforce purpose.</p>\n</section>\n\n<button>Default</button>\n<input type=\"button\" value=\"<input>\"/>\n<button>\n  <svg viewBox=\"0 0 24 24\" stroke=\"currentColor\" width=\"24\" height=\"24\" aria-hidden=\"true\">\n    <path d=\"M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z\" />\n  </svg>\n  Icon\n</button>\n<button type=\"submit\">Submit</button>\n<button type=\"button\">Type Button</button>\n<button type=\"reset\">Reset</button>\n<button disabled>Disabled</button>\n<button class=\"btn-custom\">Custom</button>\n<input type=\"file\">\n", "demo.js": ""}', '{}', '{"original_path": "patterns/components/buttons"}'), ('"carousel"', '"components"', '"vanilla"', '{"demo.css": ":where(.gui-carousel) {\n  --_carousel-item-size: 80%;\n  --_carousel-gutters: max(4rem, calc((100% - var(--_carousel-item-size)) / 2));\n  --_carousel-scrollbar-gutter: var(--size-6);\n  --_carousel-pagination-size: var(--size-8);\n\n  display: grid;\n  grid-template-columns: [carousel-gutter] var(--_carousel-gutters) 1fr [carousel-gutter] var(--_carousel-gutters);\n  grid-template-rows:\n    [carousel-scroller] 1fr\n    [carousel-pagination] var(--_carousel-pagination-size);\n\n  &:focus-visible {\n    outline-offset: -5px;\n  }\n\n  /* configuration handlers */\n  &[carousel-pagination=\"gallery\"] {\n    --_carousel-pagination-size: var(--size-10);\n\n    & > .gui-carousel--pagination {\n      -webkit-mask-image: linear-gradient(to right, #0000 0%, #000 5%, 95%, #000, #0000);\n    }\n  }\n\n  &[carousel-pagination=\"none\"] {\n    grid-template-rows: [carousel-scroller] 1fr;\n\n    & > .gui-carousel--pagination {\n      display: none;\n    }\n  }\n\n  &[carousel-controls=\"none\"] {\n    grid-template-columns: 0 1fr 0;\n\n    & > .gui-carousel--controls {\n      display: none;\n    }\n  }\n\n  &[carousel-scrollbar=\"none\"] {\n    --_carousel-pagination-size: var(--size-5);\n\n    & > .gui-carousel--scroller {\n      scrollbar-width: none;\n\n      &::-webkit-scrollbar {\n        display: none;\n      }\n    }\n\n    & > .gui-carousel--pagination {\n      place-self: start center;\n    }\n  }\n\n  &[carousel-snapstop=\"always\"] .gui-carousel--snap {\n    scroll-snap-stop: always;\n  }\n}\n\n:where(.gui-carousel--scroller) {\n  grid-row: 1;\n  grid-column: 1/-1;\n\n  display: grid;\n  grid-auto-columns: 100%;\n  grid-auto-flow: column;\n  align-items: center;\n  gap: var(--_carousel-gutters);\n\n  padding-block: var(--size-2) var(--_carousel-scrollbar-gutter);\n  overflow-x: auto;\n  overscroll-behavior-x: contain;\n  scroll-snap-type: x mandatory;\n  scroll-padding-inline: var(--_carousel-gutters);\n  padding-inline: var(--_carousel-gutters);\n\n  @media (--motionOK) {\n    scroll-behavior: smooth;\n  }\n}\n\n:where(.gui-carousel--snap) {\n  scroll-snap-align: center;\n}\n\n:where(.gui-carousel--controls) {\n  display: flex;\n  justify-content: space-between;\n  padding-inline: var(--_carousel-gutters);\n  display: contents;\n\n  & > .gui-carousel--control {\n    margin-block-end: var(--_carousel-scrollbar-gutter);\n\n    &:not([disabled=\"true\"]):active {\n      transform: scale(.95);\n    }\n  }\n}\n\n:where(.gui-carousel--control) {\n  --_shadow-size: 0;\n  --_shadow-highlight-light: hsl(0 0% 50% / 10%);\n  --_shadow-highlight-dark: hsl(0 0% 100% / 20%);\n  --_shadow-highlight: var(--_shadow-highlight-light);\n\n  grid-row: 1;\n  place-self: center;\n  background: var(--surface-1);\n  color: var(--text-2);\n  inline-size: var(--size-8);\n  aspect-ratio: var(--ratio-square);\n  border-radius: var(--radius-round);\n  box-shadow: 0 0 0 var(--_shadow-size) var(--_shadow-highlight);\n  border: var(--border-size-1) solid transparent;\n  text-indent: 10ch;\n  padding: 0;\n  overflow: hidden;\n  z-index: var(--layer-1);\n  transition: opacity .5s var(--ease-2) .5s;\n\n  @media (--motionOK) {\n    transition:\n      opacity .5s var(--ease-2) .5s,\n      transform .2s var(--ease-4),\n      box-shadow .2s var(--ease-4),\n      outline-offset 145ms var(--ease-2)\n    ;\n  }\n\n  @media (--OSdark) {\n    --_shadow-highlight: var(--_shadow-highlight-dark);\n  }\n\n  &:hover {\n    --_shadow-size: 6px;\n  }\n\n  &.--previous {\n    grid-column: 1;\n  }\n\n  &.--next {\n    grid-column: 3;\n  }\n\n  @nest [dir=\"rtl\"] & > svg {\n    transform: rotateY(180deg);\n  }\n\n  &[disabled] {\n    cursor: not-allowed;\n    transition-delay: 0s;\n\n    & > svg {\n      opacity: .25;\n    }\n  }\n\n  &:not([disabled]):is(:hover, :focus-visible) {\n    color: var(--link);\n  }\n\n  &:not([disabled]) svg > path {\n    @media (--motionOK) {\n      --_transform: translateX(var(--_x)) scale(.95);\n      transition: transform .5s var(--ease-squish-3);\n      transform-origin: center center;\n    }\n  }\n\n  &[aria-label=\"Next Item\"]:not([disabled]):is(:hover, :focus-visible) svg > path {\n    --_x: 2px;\n    transform: var(--_transform);\n  }\n\n  &[aria-label=\"Previous Item\"]:not([disabled]):is(:hover, :focus-visible) svg > path {\n    --_x: -2px;\n    transform: var(--_transform);\n  }\n}\n\n:where(.gui-carousel--pagination) {\n  grid-column: 1/-1;\n  place-self: center;\n\n  display: grid;\n  grid-auto-flow: column;\n  gap: var(--size-2);\n\n  max-inline-size: 100%;\n  overflow-x: auto;\n  overscroll-behavior-x: contain;\n\n  padding-block: var(--size-2);\n  padding-inline: var(--size-4);\n\n  scrollbar-width: none;\n\n  &::-webkit-scrollbar {\n    display: none;\n  }\n\n  @media (--motionOK) {\n    scroll-behavior: smooth;\n  }\n\n  @nest [carousel-pagination=\"gallery\"] & {\n    margin-block-end: 0;\n  }\n\n  & > [aria-selected=\"true\"] {\n    background: var(--link);\n  }\n\n  & > [aria-selected=\"false\"] {\n    transform: scale(.75);\n  }\n\n  & > button {\n    inline-size: var(--size-3);\n    background-color: var(--surface-4);\n    border: var(--border-size-1) solid transparent;\n\n    &.--gallery {\n      inline-size: var(--size-fluid-5);\n      border-radius: var(--radius-2);\n      border: none;\n      background-origin: border-box;\n      background-size: cover;\n    }\n  }\n}\n\n@keyframes gui-carousel--control-keypress {\n  0%  { outline-offset: 5px }\n  50% { outline-offset: 0; }\n}\n\n@keyframes carousel-scrollstart {\n  from { scroll-snap-align: center }\n  to   { scroll-snap-align: unset }\n}\n", "demo.html": "<div class=\"gui-carousel\" carousel-pagination=\"dots\" carousel-controls=\"auto\" carousel-scrollbar=\"auto\"\n  carousel-snapstop=\"auto\" aria-label=\"Featured Items Carousel\">\n  <div class=\"gui-carousel--scroller\">\n\n    <div class=\"gui-carousel--snap\">\n      <figure class=\"animate-visibility captioned-image\">\n        <img loading=\"lazy\" width=\"1280\" height=\"720\" src=\"https://picsum.photos/seed/this/1280/720.webp\"\n          alt=\"Blue ocean with a large wave\">\n        <figcaption>\n          <a href=\"#\">Learn more about large ocean waves</a>\n        </figcaption>\n      </figure>\n    </div>\n\n    <div class=\"gui-carousel--snap\">\n      <figure class=\"animate-visibility captioned-image\">\n        <img loading=\"lazy\" width=\"1280\" height=\"720\" src=\"https://picsum.photos/seed/is/1280/720.webp\"\n          alt=\"Frosty orange desert sunset\">\n        <figcaption>\n          <a href=\"#\">Learn more about warm deserts</a>\n        </figcaption>\n      </figure>\n    </div>\n\n    <div class=\"gui-carousel--snap\">\n      <figure class=\"animate-visibility captioned-image\">\n        <img loading=\"lazy\" width=\"1280\" height=\"720\" src=\"https://picsum.photos/seed/a/1280/720.webp\"\n          alt=\"African sahara with a giraffe\">\n        <figcaption>\n          <a href=\"#\">Learn more about giraffe''s</a>\n        </figcaption>\n      </figure>\n    </div>\n\n  </div>\n</div>\n", "demo.js": "import {scrollend} from ''https://cdn.jsdelivr.net/gh/argyleink/scrollyfills@latest/dist/scrollyfills.modern.js''\n\nexport default class Carousel {\n  constructor(element) {\n    this.elements = {\n      root:       element,\n      scroller:   element.querySelector(''.gui-carousel--scroller''),\n      snaps:      element.querySelectorAll(''.gui-carousel--snap''),\n      previous:   null, // generated in #createControl\n      next:       null, // generated in #createControl\n      pagination: null, // generated in #createPagination\n    }\n\n    this.current = undefined        // set in #initializeState\n    this.hasIntersected = new Set() // holds intersection results used on scrollend\n\n    this.elements.root.setAttribute(''tabindex'', -1)\n    this.elements.root.setAttribute(''aria-roledescription'', ''carousel'')\n\n    this.elements.scroller.setAttribute(''role'', ''group'')\n    this.elements.scroller.setAttribute(''aria-label'', ''Items Scroller'')\n    this.elements.scroller.setAttribute(''aria-live'', ''Polite'')\n\n    this.#createObservers()\n    this.#createPagination()\n    this.#createControls()\n    this.#initializeState()\n    this.#listen()\n    this.#synchronize()\n  }\n\n  #synchronize() {\n    for (let observation of this.hasIntersected) {\n      // toggle inert when it''s not intersecting\n      observation.target\n        .toggleAttribute(''inert'', !observation.isIntersecting)\n\n      // toggle aria-selected on pagination dots\n      const dot = this.elements.pagination\n        .children[this.#getElementIndex(observation.target)]\n\n      dot.setAttribute(''aria-selected'', observation.isIntersecting)\n      dot.setAttribute(''tabindex'', !observation.isIntersecting ? ''-1'' : ''0'')\n\n      // stash the intersecting snap element\n      if (observation.isIntersecting) {\n        this.current = observation.target\n        this.goToElement({\n          scrollport: this.elements.pagination,\n          element: dot,\n        })\n      }\n    }\n\n    this.#updateControls()\n    this.hasIntersected.clear()\n  }\n\n  goNext() {\n    const next = this.current.nextElementSibling\n\n    if (this.current === next)\n      return\n\n    if (next) {\n      this.goToElement({\n        scrollport: this.elements.scroller,\n        element: next,\n      })\n      this.current = next\n    }\n    else {\n      console.log(''at the end'')\n    }\n  }\n\n  goPrevious() {\n    const previous = this.current.previousElementSibling\n\n    if (this.current === previous)\n      return\n\n    if (previous) {\n      this.goToElement({\n        scrollport: this.elements.scroller,\n        element: previous,\n      })\n      this.current = previous\n    }\n    else {\n      console.log(''at the beginning'')\n    }\n  }\n\n  goToElement({scrollport, element}) {\n    const dir = this.#documentDirection()\n\n    const delta = Math.abs(scrollport.offsetLeft - element.offsetLeft)\n    const scrollerPadding = parseInt(getComputedStyle(scrollport)[''padding-left''])\n\n    const pos = scrollport.clientWidth / 2 > delta\n      ? delta - scrollerPadding\n      : delta + scrollerPadding\n\n    scrollport.scrollTo(dir === ''ltr'' ? pos : pos*-1, 0)\n  }\n\n  #updateControls() {\n    const {lastElementChild:last, firstElementChild:first} = this.elements.scroller\n\n    const isAtEnd   = this.current === last\n    const isAtStart = this.current === first\n\n    // before we possibly disable a button\n    // shift the focus to the complimentary button\n    if (document.activeElement === this.elements.next && isAtEnd)\n      this.elements.previous.focus()\n    else if (document.activeElement === this.elements.previous && isAtStart)\n      this.elements.next.focus()\n\n    this.elements.next.toggleAttribute(''disabled'', isAtEnd)\n    this.elements.previous.toggleAttribute(''disabled'', isAtStart)\n  }\n\n  #listen() {\n    // observe children intersection\n    for (let item of this.elements.snaps)\n      this.carousel_observer.observe(item)\n\n    // watch document for removal of this carousel node\n    this.mutation_observer.observe(document, {\n      childList: true,\n      subtree: true,\n    })\n\n    // scrollend