 @media (--motionOK) {\n    animation: var(--animation-scale-down) forwards;\n    animation-timing-function: var(--ease-squish-3);\n  }\n\n  @media (--OSdark) {\n    border-block-start: var(--border-size-1) solid var(--surface-3);\n  }\n\n  @media (--md-n-below) {\n    &[modal-mode=\"mega\"] {\n      margin-block-end: 0;\n      border-end-end-radius: 0;\n      border-end-start-radius: 0;\n\n      @media (--motionOK) {\n        animation: var(--animation-slide-out-down) forwards;\n        animation-timing-function: var(--ease-squish-2);\n      }\n    }\n  }\n\n  &:not([open]) {\n    pointer-events: none;\n    opacity: 0;\n  }\n\n  &[modal-mode=\"mega\"]::backdrop {\n    backdrop-filter: blur(25px);\n  }\n\n  &[modal-mode=\"mini\"]::backdrop {\n    backdrop-filter: none;\n  }\n\n  &::backdrop {\n    transition: backdrop-filter .5s ease;\n  }\n\n  &[loading] {\n    visibility: hidden;\n  }\n\n  &[open] {\n    @media (--motionOK) {\n      animation: var(--animation-slide-in-up) forwards;\n    }\n  }\n\n  & > form {\n    display: grid;\n    grid-template-rows: auto 1fr auto;\n    align-items: start;\n    max-block-size: 80vh;\n    max-block-size: 80dvb;\n\n    & > article {\n      overflow-y: auto;\n      max-block-size: 100%; /* safari */\n      overscroll-behavior-y: contain;\n      display: grid;\n      justify-items: flex-start;\n      gap: var(--size-3);\n      box-shadow: var(--shadow-2);\n      z-index: var(--layer-1);\n      padding-inline: var(--size-5);\n      padding-block: var(--size-3);\n\n      @media (--OSlight) {\n        background: var(--surface-1);\n\n        &::-webkit-scrollbar {\n          background: var(--surface-1);\n        }\n      }\n\n      @media (--OSdark) {\n        border-block-start: var(--border-size-1) solid var(--surface-3);\n      }\n    }\n\n    & > header {\n      display: flex;\n      gap: var(--size-3);\n      justify-content: space-between;\n      align-items: flex-start;\n      padding-block: var(--size-3);\n      padding-inline: var(--size-5);\n\n      & > button {\n        border-radius: var(--radius-round);\n        padding: .75ch;\n        aspect-ratio: 1;\n        flex-shrink: 0;\n        place-items: center;\n        stroke: currentColor;\n        stroke-width: 3px;\n      }\n    }\n\n    & > footer {\n      display: flex;\n      flex-wrap: wrap;\n      gap: var(--size-3);\n      justify-content: space-between;\n      align-items: flex-start;\n      padding-inline: var(--size-5);\n      padding-block: var(--size-3);\n\n      & > menu {\n        display: flex;\n        flex-wrap: wrap;\n        gap: var(--size-3);\n        padding-inline-start: 0;\n\n        &:only-child {\n          margin-inline-start: auto;\n        }\n\n        @media (max-width: 410px) {\n          & button[type=\"reset\"] {\n            display: none;\n          }\n        }\n      }\n    }\n\n    & > :is(header, footer) {\n      background-color: var(--surface-2);\n\n      @media (--OSdark) {\n        background-color: var(--surface-1);\n      }\n    }\n  }\n}\n", "demo.html": "<dialog id=\"MegaDialog\" inert loading modal-mode=\"mega\"> \n  <form method=\"dialog\">\n    <header> \n      <section class=\"icon-headline\">\n        <svg aria-hidden=\"true\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\">\n          <path d=\"M16 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2\"></path>\n          <circle cx=\"8.5\" cy=\"7\" r=\"4\"></circle>\n          <line x1=\"20\" y1=\"8\" x2=\"20\" y2=\"14\"></line>\n          <line x1=\"23\" y1=\"11\" x2=\"17\" y2=\"11\"></line>\n        </svg>\n        <h3>New User</h3>\n      </section>\n      <button onclick=\"this.closest(''dialog'').close(''close'')\" type=\"button\" title=\"Close dialog\"> \n        <title>Close dialog icon</title>\n        <svg width=\"24\" height=\"24\" viewBox=\"0 0 24 24\">\n          <line x1=\"18\" y1=\"6\" x2=\"6\" y2=\"18\"/>\n          <line x1=\"6\" y1=\"6\" x2=\"18\" y2=\"18\"/>\n        </svg>\n      </button>\n    </header>\n    <article>\n      <section class=\"labelled-input\">\n        <label for=\"userimage\">Upload an image</label>\n        <input id=\"userimage\" name=\"userimage\" type=\"file\">\n      </section>\n      <small><b>*</b> Maximum upload 1mb</small>\n    </article>\n    <footer>\n      <menu>\n        <button type=\"reset\" value=\"clear\">Clear</button>\n      </menu>\n      <menu>\n        <button autofocus type=\"button\" onclick=\"this.closest(''dialog'').close(''cancel'')\">Cancel</button>\n        <button type=\"submit\" value=\"confirm\">Confirm</button>\n      </menu>\n    </footer>\n  </form>\n</dialog>\n\n<dialog id=\"MiniDialog\" inert loading modal-mode=\"mini\"> \n  <form method=\"dialog\">\n    <article>\n      <section class=\"warning-message\">\n        <svg aria-hidden=\"true\" width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" >\n          <title>A warning icon</title>\n          <path d=\"M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z\"></path>\n          <line x1=\"12\" y1=\"9\" x2=\"12\" y2=\"13\"></line>\n          <line x1=\"12\" y1=\"17\" x2=\"12.01\" y2=\"17\"></line>\n        </svg>\n        <p>Are you sure you want to remove this user?</p>\n      </section>\n    </article>\n    <footer>\n      <menu>\n        <button autofocus type=\"button\" onclick=\"this.closest(''dialog'').close(''cancel'')\">Cancel</button>\n        <button type=\"submit\" value=\"confirm\">Confirm</button>\n      </menu>\n    </footer>\n  </form>\n</dialog>", "demo.js": "// custom events to be added to <dialog>\nconst dialogClosingEvent = new Event(''closing'')\nconst dialogClosedEvent  = new Event(''closed'')\nconst dialogOpeningEvent = new Event(''opening'')\nconst dialogOpenedEvent  = new Event(''opened'')\nconst dialogRemovedEvent = new Event(''removed'')\n\n// track opening\nconst dialogAttrObserver = new MutationObserver((mutations, observer) => {\n  mutations.forEach(async mutation => {\n    if (mutation.attributeName === ''open'') {\n      const dialog = mutation.target\n\n      const isOpen = dialog.hasAttribute(''open'')\n      if (!isOpen) return\n\n      dialog.removeAttribute(''inert'')\n\n      // set focus\n      const focusTarget = dialog.querySelector(''[autofocus]'')\n      focusTarget\n        ? focusTarget.focus()\n        : dialog.querySelector(''button'').focus()\n\n      dialog.dispatchEvent(dialogOpeningEvent)\n      await animationsComplete(dialog)\n      dialog.dispatchEvent(dialogOpenedEvent)\n    }\n  })\n})\n\n// track deletion\nconst dialogDeleteObserver = new MutationObserver((mutations, observer) => {\n  mutations.forEach(mutation => {\n    mutation.removedNodes.forEach(removedNode => {\n      if (removedNode.nodeName === ''DIALOG'') {\n        removedNode.removeEventListener(''click'', lightDismiss)\n        removedNode.removeEventListener(''close'', dialogClose)\n        removedNode.dispatchEvent(dialogRemovedEvent)\n      }\n    })\n  })\n})\n\n// wait for all dialog animations to complete their promises\nconst animationsComplete = element =>\n  Promise.allSettled(\n    element.getAnimations().map(animation => \n      animation.finished))\n\n// click outside the dialog handler\nconst lightDismiss = ({target:dialog}) => {\n  if (dialog.nodeName === ''DIALOG'')\n    dialog.close(''dismiss'')\n}\n\nconst dialogClose = async ({target:dialog}) => {\n  dialog.setAttribute(''inert'', '''')\n  dialog.dispatchEvent(dialogClosingEvent)\n\n  await animationsComplete(dialog)\n\n  dialog.dispatchEvent(dialogClosedEvent)\n}\n\n// page load dialogs setup\nexport default async function (dialog) {\n  dialog.addEventListener(''click'', lightDismiss)\n  dialog.addEventListener(''close'', dialogClose)\n\n  dialogAttrObserver.observe(dialog, { \n    attributes: true,\n  })\n\n  dialogDeleteObserver.observe(document.body, {\n    attributes: false,\n    subtree: false,\n    childList: true,\n  })\n\n  // remove loading attribute\n  // prevent page load @keyframes playing\n  await animationsComplete(dialog)\n  dialog.removeAttribute(''loading'')\n}"}', '{}', '{"original_path": "patterns/components/dialog"}'), ('"game-menu"', '"components"', '"vanilla"', '{"demo.css": "body {\n  perspective: 40vw;\n}\n\n.threeD-button-set {\n  --y:;\n  --x:;\n  --distance: 1px;\n  --theme: hsl(180 100% 50%);\n  --theme-bg: hsl(180 100% 50% / 25%);\n  --theme-bg-hover: hsl(180 100% 50% / 40%);\n  --theme-text: white;\n  --theme-shadow: hsl(180 100% 10% / 25%);\n\n  --_max-rotateY: 10deg;\n  --_max-rotateX: 15deg;\n  --_btn-bg: var(--theme-bg);\n  --_btn-bg-hover: var(--theme-bg-hover);\n  --_btn-text: var(--theme-text);\n  --_btn-text-shadow: var(--theme-shadow);\n  --_bounce-ease: cubic-bezier(.5, 1.75, .75, 1.25);\n\n  /* remove <ul> margins */\n  margin: 0;\n\n  /* vertical rag-right layout */\n  display: flex;\n  flex-direction: column;\n  align-items: flex-start;\n  gap: 2.5vh;\n  \n  /* create 3D space context */\n  transform-style: preserve-3d;\n\n  /* clamped menu rotation to not be too extreme */\n  transform: \n    rotateY(\n      clamp(\n        calc(var(--_max-rotateY) * -1), \n        var(--y), \n        var(--_max-rotateY)\n      )\n    ) \n    rotateX(\n      clamp(\n        calc(var(--_max-rotateX) * -1), \n        var(--x), \n        var(--_max-rotateX)\n      )\n    )\n  ;\n\n  /* removes Safari focus ring on <ul> after button interaction */\n  &:focus {\n    outline: none;\n  }\n  \n  @media (--motionOK) {\n    will-change: transform;\n    transition: transform .1s ease;\n    animation: rotate-y 5s ease-in-out infinite;\n  }\n\n  @media (--dark) {\n    --theme: hsl(255 53% 50%);\n    --theme-bg: hsl(255 53% 71% / 25%);\n    --theme-bg-hover: hsl(255 53% 50% / 40%);\n    --theme-shadow: hsl(255 53% 10% / 25%);\n  }\n\n  @media (--HDcolor) {\n    @supports (color: color(display-p3 0 0 0)) {\n      --theme: color(display-p3 .4 0 .9);\n    }\n  }\n}\n\n.threeD-button-set > li {\n  /* change display type from list-item */\n  display: inline-flex;\n\n  /* create context for button pseudos */\n  position: relative;\n\n  /* create 3D space context */\n  transform-style: preserve-3d; \n}\n  \n.threeD-button-set button {\n  /* strip out default button styles */\n  appearance: none;\n  outline: none;\n  border: none;\n  -webkit-tap-highlight-color: transparent;\n  \n  /* bring in brand styles via props */\n  background-color: var(--_btn-bg);\n  color: var(--_btn-text);\n  text-shadow: 0 1px 1px var(--_btn-text-shadow);\n\n  font-size: min(5vmin, 3rem);\n  font-family: Audiowide;\n  padding-block: .75ch;\n  padding-inline: 2ch;\n  border-radius: 5px 20px;\n\n  /* prepare for 3D perspective transforms */\n  transform: translateZ(var(--distance));\n  transform-style: preserve-3d;\n  \n  &:is(:hover, :focus-visible):not(:active) {\n    /* subtle distance plus bg color change on hover/focus */\n    --distance: 15px;\n    background-color: var(--_btn-bg-hover);\n\n    /* if motion is OK, setup transitions and increase distance */\n    @media (--motionOK) {\n      --distance: 3vmax;\n\n      transition-timing-function: var(--_bounce-ease);\n      transition-duration: .4s;\n\n      &::after  { transition-duration: .5s }\n      &::before { transition-duration: .3s }\n    }\n  }\n  \n  &::after,\n  &::before {\n    /* create empty element */\n    content: '''';\n    opacity: .8;\n\n    /* cover the parent (button) */\n    position: absolute;\n    inset: 0;\n\n    /* style the element for border accents */\n    border: 1px solid var(--theme);\n    border-radius: 5px 20px;\n\n    /* move in Z space with a multiplier */\n    transform: translateZ(calc(var(--distance) / 3));\n\n    /* if motion is OK, transition the Z space move */\n    @media (--motionOK) {\n      transition: transform .1s ease-out;   \n    }\n  }\n  \n  /* exceptions for one of the pseudo elements */\n  /* this will be pushed back and have a thicker border */\n  &::before {\n    border-width: 3px;\n    transform: translateZ(calc(var(--distance) / 3 * -1));\n\n    /* in dark mode, it glows! */\n    @media (--dark) {\n      box-shadow: \n        0 0 25px var(--theme), \n        inset 0 0 25px var(--theme);\n    }\n  }\n  \n  @media (--motionOK) {\n    will-change: transform;\n    transition: \n      transform .2s ease,\n      background-color .5s ease;\n  }\n}\n\n@keyframes rotate-y {\n  50% {\n    transform: rotateY(15deg) rotateX(-6deg);\n  }\n}", "demo.html": "<ul class=\"threeD-button-set\">\n  <li><button>New Game</button></li>\n  <li><button>Continue</button></li>\n  <li><button>Online</button></li>\n  <li><button>Settings</button></li>\n  <li><button>Quit</button></li>\n</ul>", "demo.js": "import {rovingIndex} from ''https://cdn.skypack.dev/roving-ux''\n   \nconst menu = document.querySelector(''.threeD-button-set'')\nconst menuRect = menu.getBoundingClientRect()\n\nconst { matches:motionOK } = window.matchMedia(\n  ''(prefers-reduced-motion: no-preference)''\n)\n\nrovingIndex({\n  element: document.querySelector(''.threeD-button-set''),\n  target: ''button'',\n})\n\nif (motionOK) {\n  window.addEventListener(''mousemove'', ({target, clientX, clientY}) => {\n    const {dx,dy} = getAngles(clientX, clientY)\n\n    menu.style.setProperty(''--x'', `${dy / 20}deg`)\n    menu.style.setProperty(''--y'', `${dx / 20}deg`)\n  })\n}\n\nconst getAngles = (clientX, clientY) => {\n  const { x, y, width, height } = menuRect \n  \n  const dx = clientX - (x + 0.5 * width)\n  const dy = clientY - (y + 0.5 * height)\n  \n  return {dx,dy}\n}"}', '{}', '{"original_path": "patterns/components/game-menu"}'), ('"loading-bar"', '"components"', '"vanilla"', '{"demo.css": "progress {\n  --_track: hsl(228 100% 90%);\n  --_track-size: min(10px, 1ex);\n  --_progress: hsl(228 100% 50%);\n  --_radius: 1e3px;\n  --_indeterminate-track: linear-gradient(to right,\n    var(--_track) 45%,\n    var(--_progress) 0%,\n    var(--_progress) 55%,\n    var(--_track) 0%\n  );\n  --_indeterminate-track-size: 225% 100%;\n  --_indeterminate-track-animation: progress-loading 2s infinite ease;\n  \n  /*  reset  */\n  appearance: none;\n  border: none;\n  \n  /*  custom style  */\n  position: relative;\n  height: var(--_track-size);\n  border-radius: var(--_radius);\n  overflow: hidden;\n\n  @media (prefers-color-scheme: dark) {\n    --_track: hsl(228 20% 30%);\n    --_progress: hsl(228 100% 75%);\n  }\n\n  &:focus-visible {\n    outline-color: var(--_progress);\n  }\n  \n  /*  Safari/Chromium  */\n  &[value]::-webkit-progress-bar {\n    background-color: var(--_track);\n  }\n  \n  &[value]::-webkit-progress-value {\n    background-color: var(--_progress);\n    transition: inline-size .25s ease-out;\n  }\n  \n  /*  Firefox  */\n  &[value]::-moz-progress-bar {\n    background-color: var(--_progress);\n  }\n  \n  /*  indeterminate  */\n  &:indeterminate::after {\n    content: \"\";\n    inset: 0;\n    position: absolute;\n    background: var(--_indeterminate-track);\n    background-size: var(--_indeterminate-track-size);\n    background-position: right; \n    animation: var(--_indeterminate-track-animation);\n  }\n  \n  /*  indeterminate Safari  */\n  &:indeterminate::-webkit-progress-bar {\n    background: var(--_indeterminate-track);\n    background-size: var(--_indeterminate-track-size);\n    background-position: right; \n    animation: var(--_indeterminate-track-animation);\n  }\n  \n  /*  indeterminate Firefox  */\n  &:indeterminate::-moz-progress-bar {\n    background: var(--_indeterminate-track);\n    background-size: var(--_indeterminate-track-size);\n    background-position: right; \n    animation: var(--_indeterminate-track-animation);\n  }\n  \n  /*  complete  */\n  &:not([max])[value=\"1\"]::before,\n  &[max=\"100\"][value=\"100\"]::before {\n    content: \"\u2713\";\n    \n    position: absolute;\n    inset-block: 0;\n    inset-inline: auto 0;\n    display: flex;\n    align-items: center;\n    padding-inline-end: max(calc(var(--_track-size) / 4), 3px);\n\n    color: white;\n    font-size: calc(var(--_track-size) / 1.25);\n  }\n}\n\n@keyframes progress-loading {\n  50% {\n    background-position: left; \n  }\n}", "demo.html": "<main id=\"loading-zone\" aria-busy=\"true\">\n  <p>Loading Level</p>\n  <div class=\"card\">\n    <label>\n      <span class=\"sr-only\">Loading progress</span>\n      <progress \n        indeterminate \n        role=\"progressbar\" \n        aria-describedby=\"loading-zone\"\n        tabindex=\"-1\"\n      >unknown</progress>\n    </label>\n  </div>\n</main>", "demo.js": "const progress = document.querySelector(''progress'')\nconst zone     = document.querySelector(''#loading-zone'')\n\nconst state = {\n  val: .1\n}\n\nconst roundDecimals = (val, places) =>\n  +(Math.round(val + \"e+\" + places)  + \"e-\" + places)\n\nconst setProgress = () => {\n  // set loading zone status\n  zone.setAttribute(''aria-busy'', state.val < 1)\n\n  // clear attributes if no value to show\n  // <progress> will show indeterminate state\n  if (state.val === null) {\n    progress.removeAttribute(''aria-valuenow'')\n    progress.removeAttribute(''value'')\n    progress.focus()\n    return\n  }\n\n  // round bad JS decimal math\n  const val = roundDecimals(state.val, 2)\n  const valPercent = val * 100 + \"%\"\n  \n  // set value for screenreaders and element values\n  progress.value = val\n  progress.setAttribute(''aria-valuenow'', valPercent)\n  progress.innerText = valPercent\n\n  // focus so screenreaders hear the announced value update\n  progress.focus()\n}"}', '{}', '{"original_path": "patterns/components/loading-bar"}'), ('"media-scroller"', '"components"', '"vanilla"', '{"demo.css": ".horizontal-media-scroller {\n  --size: 150px;\n\n  display: grid;\n  grid-auto-flow: column;\n  gap: calc(var(--gap) / 2);\n  margin: 0;\n\n  padding-inline-start: var(--gap);\n  padding-inline-end: var(--gap);\n  padding-block-start: calc(var(--gap) / 2);\n  padding-block-end: calc(var(--gap) / 2);\n\n  overflow-x: auto;\n  overscroll-behavior-inline: contain;\n  scroll-snap-type: inline mandatory;\n  sc