 placeholder image\" loading=\"lazy\" src=\"https://picsum.photos/500/500?27\">\n      </picture>\n      <figcaption>Penny Dreadful</figcaption>\n    </figure></a></li>\n    <li><a href=\"#\"><figure>\n      <picture>\n        <img alt=\"A placeholder image\" loading=\"lazy\" src=\"https://picsum.photos/500/500?28\">\n      </picture>\n      <figcaption>Castle Rock</figcaption>\n    </figure></a></li>\n    <li><a href=\"#\"><figure>\n      <picture>\n        <img alt=\"A placeholder image\" loading=\"lazy\" src=\"https://picsum.photos/500/500?29\">\n      </picture>\n      <figcaption>The Walking Dead</figcaption>\n    </figure></a></li>\n    <li><a href=\"#\"><figure>\n      <picture>\n        <img alt=\"A placeholder image\" loading=\"lazy\" src=\"https://picsum.photos/500/500?210\">\n      </picture>\n      <figcaption>Fear The Walking Dead</figcaption>\n    </figure></a></li>\n  </ul>\n</section>", "demo.js": "import {rovingIndex} from \"https://cdn.skypack.dev/roving-ux\"\n\ndocument.querySelectorAll(''.horizontal-media-scroller'')\n  .forEach(scroller => rovingIndex({\n    element: scroller,\n    target: ''a'',\n  }))\n"}', '{}', '{"original_path": "patterns/components/media-scroller"}'), ('"multi-select"', '"components"', '"vanilla"', '{"demo.css": "main {\n  display: grid;\n  grid-template-columns: max-content 1fr;\n  gap: 5vmin;\n  align-items: flex-start;\n\n  & > header {\n    grid-column: 1 / -1;\n  }\n\n  @media (orientation: portrait) {\n    grid-template-columns: 1fr;\n  }\n\n  @media (--useSelect) {\n    & > article {\n      grid-row: 3;\n      grid-column: 1 / -1;\n    }\n  }\n}\n\narticle {\n  --size: min(300px, calc(25% - 2ch));\n  margin: -1ch;\n\n  & > span {\n    will-change: transform;\n    background: hsl(0 0% 50% / 25%);\n    border-radius: 10px;\n    inline-size: var(--size);\n    block-size: 15ch;\n    margin: 1ch;\n\n    @media (orientation: portrait) {\n      --size: calc(50% - 2ch);\n    }\n\n    @supports (aspect-ratio: 1) {\n      block-size: auto;\n      aspect-ratio: 1;\n    }\n  }\n}\n\nheader {\n  display: grid;\n  gap: 1ch;\n}\n\naside {\n  counter-reset: filters;\n\n  & :checked {\n    counter-increment: filters; \n  }\n\n  & #applied-filters::before {\n    content: counter(filters) \" filters \";\n  }\n}\n\nfieldset:first-of-type {\n  margin-block-start: -5px;\n}\n\n[role=\"status\"] {\n  @media (--useSelect) {\n    display: none;\n  }\n}\n\n.sr-only {\n  inline-size: 0;\n  block-size: 0;\n  overflow: hidden;\n}", "demo.html": "<main>\n  <header>\n    <h1>Lighting</h1>\n    <small>Find your perfect light</small>\n  </header>\n  <aside>\n    <form>\n      <select multiple=\"true\" title=\"Filter results by category\">\n        <optgroup label=\"New\">\n          <option value=\"last 30 days\">Last 30 Days</option>\n          <option value=\"last 6 months\">Last 6 Months</option>\n        </optgroup>\n        <optgroup label=\"Lamps\">\n          <option value=\"table lamps\">Table Lamps</option>\n          <option value=\"desk lamps\">Desk Lamps</option>\n          <option value=\"floor lamps\">Floor Lamps</option>\n        </optgroup>\n        <optgroup label=\"Ceiling\">\n          <option value=\"chandeliers\">Chandeliers</option>\n          <option value=\"pendant\">Pendant</option>\n          <option value=\"flush\">Flush</option>\n          <option value=\"fans\">Fans</option>\n        </optgroup>\n        <optgroup label=\"By Room\">\n          <option value=\"bedroom\">Bedroom</option>\n          <option value=\"dining room\">Dining Room</option>\n          <option value=\"kitchen\">Kitchen</option>\n          <option value=\"living room\">Living Room</option>\n          <option value=\"bathroom\">Bathroom</option>\n          <option value=\"entryway\">Entryway</option>\n          <option value=\"outdoor\">Outdoor</option>\n        </optgroup>\n        <optgroup label=\"Kids\">\n          <option value=\"lamps\">Lamps</option>\n          <option value=\"night lights\">Night Lights</option>\n          <option value=\"ceiling\">Ceiling</option>\n        </optgroup>\n      </select>\n      \n      <fieldset>\n        <legend>New</legend>\n        <div>\n          <input type=\"checkbox\" id=\"last-30-days\" name=\"new\" value=\"last 30 days\">\n          <label for=\"last-30-days\">Last 30 Days</label>\n        </div>\n        <div>\n          <input type=\"checkbox\" id=\"last-6-months\" name=\"new\" value=\"last 6 months\">\n          <label for=\"last-6-months\">Last 6 Months</label>\n        </div>\n      </fieldset>\n      <fieldset>\n        <legend>Lamps</legend>\n        <div>\n          <input type=\"checkbox\" id=\"table-lamps\" name=\"lamps\" value=\"table lamps\">\n          <label for=\"table-lamps\">Table Lamps</label>\n        </div>\n        <div>\n          <input type=\"checkbox\" id=\"desk-lamps\" name=\"lamps\" value=\"desk lamps\">\n          <label for=\"desk-lamps\">Desk Lamps</label>\n        </div>\n        <div>\n          <input type=\"checkbox\" id=\"floor-lamps\" name=\"lamps\" value=\"floor lamps\">\n          <label for=\"floor-lamps\">Floor Lamps</label>\n        </div>\n      </fieldset>\n      <fieldset>\n        <legend>Ceiling</legend>\n        <div>\n          <input type=\"checkbox\" id=\"chandeliers\" name=\"ceiling\" value=\"chandeliers\">\n          <label for=\"chandeliers\">Chandeliers</label>\n        </div>\n        <div>\n          <input type=\"checkbox\" id=\"pendant\" name=\"ceiling\" value=\"pendant\">\n          <label for=\"pendant\">Pendant</label>\n        </div>\n        <div>\n          <input type=\"checkbox\" id=\"flush\" name=\"ceiling\" value=\"flush\">\n          <label for=\"flush\">Flush</label>\n        </div>\n        <div>\n          <input type=\"checkbox\" id=\"fans\" name=\"ceiling\" value=\"fans\">\n          <label for=\"fans\">Fans</label>\n        </div>\n      </fieldset>\n      <fieldset>\n        <legend>By Room</legend>\n        <div>\n          <input type=\"checkbox\" id=\"bedroom\" name=\"by room\" value=\"bedroom\">\n          <label for=\"bedroom\">Bedroom</label>\n        </div>\n        <div>\n          <input type=\"checkbox\" id=\"dining-room\" name=\"by room\" value=\"dining room\">\n          <label for=\"dining-room\">Dining Room</label>\n        </div>\n        <div>\n          <input type=\"checkbox\" id=\"kitchen\" name=\"by room\" value=\"kitchen\">\n          <label for=\"kitchen\">Kitchen</label>\n        </div>\n        <div>\n          <input type=\"checkbox\" id=\"living-room\" name=\"by room\" value=\"living room\">\n          <label for=\"living-room\">Living Room</label>\n        </div>\n        <div>\n          <input type=\"checkbox\" id=\"bathroom\" name=\"by room\" value=\"bathroom\">\n          <label for=\"bathroom\">Bathroom</label>\n        </div>\n        <div>\n          <input type=\"checkbox\" id=\"entryway\" name=\"by room\" value=\"entryway\">\n          <label for=\"entryway\">Entryway</label>\n        </div>\n        <div>\n          <input type=\"checkbox\" id=\"outdoor\" name=\"by room\" value=\"outdoor\">\n          <label for=\"outdoor\">Outdoor</label>\n        </div>\n      </fieldset>\n      <fieldset>\n        <legend>Kids</legend>\n        <div>\n          <input type=\"checkbox\" id=\"lamps\" name=\"kids\" value=\"lamps\">\n          <label for=\"lamps\">Lamps</label>\n        </div>\n        <div>\n          <input type=\"checkbox\" id=\"night-lights\" name=\"kids\" value=\"night lights\">\n          <label for=\"night-lights\">Night Lights</label>\n        </div>\n        <div>\n          <input type=\"checkbox\" id=\"ceiling\" name=\"kids\" value=\"ceiling\">\n          <label for=\"ceiling\">Ceiling</label>\n        </div>\n      </fieldset>\n    </form>\n    <div role=\"status\" class=\"sr-only\" id=\"applied-filters\"></div>\n  </aside>\n  <article>\n    <span class=\"last-30-days table-lamps\"></span>\n    <span class=\"last-6-months desk-lamps\"></span>\n    <span class=\"floor-lamps\"></span>\n    <span class=\"last-6-months chandeliers\"></span>\n    <span class=\"pendant last-6-months\"></span>\n    <span class=\"flush fans\"></span>\n    <span class=\"fans pendant table-lamps\"></span>\n    <span class=\"bedroom\"></span>\n    <span class=\"dining-room last-30-days chandeliers\"></span>\n    <span class=\"kitchen lamps\"></span>\n    <span class=\"living-room\"></span>\n    <span class=\"bathroom living-room chandeliers desk-lamps\"></span>\n    <span class=\"bathroom table-lamps desk-lamps\"></span>\n    <span class=\"entryway last-30-days\"></span>\n    <span class=\"outdoor desk-lamps\"></span>\n    <span class=\"lamps last-30-days\"></span>\n    <span class=\"night-lights table-lamps\"></span>\n    <span class=\"ceiling last-30-days\"></span>\n    <span class=\"floor-lamps table-lamps\"></span>\n    <span class=\"floor-lamps last-6-months\"></span>\n    <span class=\"dining-room last-30-days chandeliers\"></span>\n    <span class=\"kitchen lamps\"></span>\n    <span class=\"living-room\"></span>\n    <span class=\"bathroom living-room chandeliers desk-lamps\"></span>\n  </article>\n</main>", "demo.js": "import ''https://unpkg.com/isotope-layout@3.0.6/dist/isotope.pkgd.min.js''\n\nconst IsotopeGrid = new Isotope( ''article'', {\n  itemSelector: ''span'',\n  layoutMode: ''fitRows'',\n  percentPosition: true\n})\n  \nconst filterGrid = query => {\n  const { matches:motionOK } = window.matchMedia(\n    ''(prefers-reduced-motion: no-preference)''\n  )\n  \n  IsotopeGrid.arrange({\n    filter: query,\n    stagger: 25,\n    transitionDuration: motionOK ? ''0.4s'' : 0,\n  })\n}\n\n// takes a <select> and returns the selection as an array\nconst prepareSelectOptions = element =>\n  Array.from(element.selectedOptions).reduce((data, opt) => {\n    data.push([opt.parentElement.label.toLowerCase(), opt.value])\n    return data\n  }, [])\n\n// <select> watcher\ndocument.querySelector(''select'').addEventListener(''input'', e => {\n  let selectData = prepareSelectOptions(e.target)\n  console.warn(''Multiselect'', selectData)\n\n  // DEMO\n  // isotope query assembly from checkbox selections\n  let query = selectData.reduce((query, val) => {\n    query.push(''.'' + val[1].split('' '').join(''-''))\n    return query\n  }, []).join('','')\n\n  filterGrid(query)\n\n  // update for assistive technology\n  let statusRoleElement = document.querySelector(''#applied-filters'')\n  let filterResults = IsotopeGrid.getFilteredItemElements().length\n\n  statusRoleElement.style.counterSet = selectData.length\n  statusRoleElement.textContent = \" giving \" + filterResults + \" results\"\n})\n\ndocument\n  .querySelector(''aside form'')\n  .addEventListener(''input'', e => {\n    if (e.target.nodeName === ''SELECT'') return\n      \n    const formData = new FormData(document.querySelector(''form''))\n    console.warn(''Checkboxes'', Array.from(formData.entries()))\n\n    // DEMO\n    // isotope query assembly from checkbox selections\n    let query = Array.from(formData.values()).reduce((query, val) => {\n      query.push(''.'' + val.split('' '').join(''-''))\n      return query\n    }, []).join('','')\n\n    filterGrid(query)\n\n    document.querySelector(''#applied-filters'').textContent = \" giving \" + IsotopeGrid.getFilteredItemElements().length + \" results\"\n  })"}', '{}', '{"original_path": "patterns/components/multi-select"}'), ('"settings"', '"components"', '"vanilla"', '{"demo.css": "@custom-media --motionOK (prefers-reduced-motion: no-preference);\n\n:root {\n  --surface1: lch(10 0 0);\n  --surface2: lch(15 0 0);\n  --surface3: lch(20 0 0);\n  --surface4: lch(25 0 0);\n\n  --text1: lch(95 0 0);\n  --text2: lch(75 0 0);\n\n  --brand: lch(64 20 237);\n  --brand-bg1: lch(70 64 349);\n  --brand-bg2: lch(60 84 300);\n\n  --brand-bg-gradient: linear-gradient(\n    to bottom, \n    var(--brand-bg1), \n    var(--brand-bg2)\n  );\n\n  --thumb-highlight-color: lch(100 0 0 / 20%);\n\n  --space-xxs: .25rem;\n  --space-xs:  .5rem;\n  --space-sm:  1rem;\n  --space-md:  1.5rem;\n  --space-lg:  2rem;\n  --space-xl:  3rem;\n  --space-xxl: 6rem;\n  \n  --isLTR: 1;\n  --isRTL: -1;\n  \n  &:dir(rtl) {\n    --isLTR: -1;\n    --isRTL: 1;\n  }\n\n  @media (prefers-color-scheme: light) {\n    & {\n      --surface1: lch(90 0 0);\n      --surface2: lch(100 0 0);\n      --surface3: lch(98 0 0);\n      --surface4: lch(85 0 0);\n\n      --text1: lch(20 0 0);\n      --text2: lch(40 0 0);\n\n      --brand: lch(64 40 237);\n      --brand-bg1: lch(50 64 349);\n      --brand-bg2: lch(40 84 300);\n\n      --thumb-highlight-color: lch(0 0 0 / 20%);\n    }\n  }\n}\n\nhtml {\n  block-size: 100%;\n  inline-size: 100%;\n}\n\nbody {\n  min-block-size: 100%;\n  min-inline-size: 100%;\n\n  box-sizing: border-box;\n  margin: 0;\n  padding-block: var(--space-xs);\n\n  background: var(--surface1);\n  color: var(--text1);\n  font-family: system-ui, sans-serif;\n}\n\nh1,h2,h3 { \n  margin: 0; \n  font-weight: 500;\n}\n\nmain {\n  display: grid;\n  gap: var(--space-xl);\n  place-content: center;\n  padding: var(--space-sm);\n\n  @media (width >= 540px) {\n    padding: var(--space-lg);\n  }\n\n  @media (width >= 800px) {\n    padding: var(--space-xl);\n  }\n}\n\nform {\n  max-width: 89vw;\n  display: grid;\n  gap: var(--space-xl) var(--space-xxl);\n  --repeat: auto-fit;\n  grid-template-columns: \n    repeat(var(--repeat), minmax(min(10ch, 100%), 35ch));\n  align-items: flex-start;\n\n  @media (orientation: landscape) and (width >= 640px) {\n    --repeat: 2;\n  }\n}\n\nsection {\n  display: grid;\n  gap: var(--space-md);\n}\n\nheader {\n  display: grid;\n  gap: var(--space-xxs);\n}\n\nfieldset {\n  border: 1px solid var(--surface4);\n  background: var(--surface4);\n  padding: 0;\n  margin: 0;\n  display: grid;\n  gap: 1px;\n  border-radius: var(--space-sm);\n  overflow: hidden;\n  transition: box-shadow .3s ease;\n\n  &:focus-within {\n    box-shadow: 0 5px 20px -10px hsl(0 0% 0% / 50%);\n  }\n}\n\ninput[type=\"range\"] {\n  --track-height: .5ex;\n  --track-fill: 0%;\n  --thumb-size: 3ex;\n  --thumb-offset: -1.25ex;\n  --thumb-highlight-size: 0px;\n\n  display: block;\n  inline-size: 100%;\n  margin: 1ex 0;\n  appearance: none;\n  background: transparent;\n  outline-offset: 5px;\n\n  @media (hover: none) {\n    --thumb-size: 30px;\n    --thumb-offset: -14px;\n  }\n\n  &::-webkit-slider-runnable-track {\n    appearance: none;\n    block-size: var(--track-height);\n    border-radius: 5ex;\n    background: \n      linear-gradient(\n        to right, \n        transparent var(--track-fill), \n        var(--surface1) 0%\n      ),\n      var(--brand-bg-gradient) fixed;\n  }\n\n  &::-moz-range-track {\n    appearance: none;\n    block-size: var(--track-height);\n    border-radius: 5ex;\n    background: \n      linear-gradient(\n        to right, \n        transparent var(--track-fill), \n        var(--surface1) 0%\n      ),\n      var(--brand-bg-gradient) fixed;\n  }\n\n  &::-webkit-slider-thumb {\n    appearance: none;\n    cursor: ew-resize;\n    border: 3px solid var(--surface3);\n    block-size: var(--thumb-size);\n    inline-size: var(--thumb-size);\n    margin-block-start: var(--thumb-offset);\n    border-radius: 50%;\n    background: var(--brand-bg-gradient) fixed;\n    box-shadow: 0 0 0 var(--thumb-highlight-size) var(--thumb-highlight-color);\n    \n    @media (--motionOK) {\n      transition: box-shadow .1s ease;\n    }\n\n    @nest .fieldset-item:focus-within & {\n      border-color: var(--surface2);\n    }\n  }\n\n  &::-moz-range-thumb {\n    appearance: none;\n    cursor: ew-resize;\n    border: 3px solid var(--surface3);\n    block-size: var(--thumb-size);\n    inline-size: var(--thumb-size);\n    margin-block-start: var(--thumb-offset);\n    border-radius: 50%;\n    background: var(--brand-bg-gradient) fixed;\n    box-shadow: 0 0 0 var(--thumb-highlight-size) var(--thumb-highlight-color);\n\n    @media (--motionOK) {\n      transition: box-shadow .1s ease;\n    }\n\n    @nest .fieldset-item:focus-within & {\n      border-color: var(--surface2);\n    }\n  }\n\n  &:is(:hover,:active) {\n    --thumb-highlight-size: 10px;\n  }\n}\n\ninput[type=\"checkbox\"] {\n  inline-size: var(--space-sm);\n  block-size: var(--space-sm);\n  margin: 0;\n  outline-offset: 5px;\n  accent-color: var(--brand);\n  position: relative;\n  transform-style: preserve-3d;\n  cursor: pointer;\n\n  &:hover::before {\n    --thumb-scale: 1;\n  }\n\n  @media (hover: none) {\n    inline-size: var(--space-md);\n    block-size: var(--space-md);\n  }\n\n  &::before {\n    --thumb-scale: .01;\n    --thumb-highlight-size: var(--space-xl);\n\n    content: \"\";\n    inline-size: var(--thumb-highlight-size);\n    block-size: var(--thumb-highlight-size);\n    clip-path: circle(50%);\n    position: absolute;\n    inset-block-start: 50%;\n    inset-inline-start: 50%;\n    background: var(--thumb-highlight-color);\n    transform-origin: center center;\n    transform: \n      translateX(calc(var(--isRTL) * 50%)) \n      translateY(-50%) \n      translateZ(-1px) \n      scale(var(--thumb-scale))\n    ;\n    will-change: transform;\n\n    @media (--motionOK) {\n      transition: transform .2s ease;\n    }\n  }\n}\n\n.fieldset-item {\n  background: var(--surface3);\n  transition: background .2s ease;\n\n  display: grid;\n  grid-template-columns: var(--space-lg) 1fr;\n  gap: var(--space-md);\n\n  padding-block: var(--space-sm);\n  padding-inline: var(--space-md);\n\n  @media (width >= 540px) {\n    grid-template-columns: var(--space-xxl) 1fr;\n    gap: var(--space-xs);\n    padding-block: var(--space-md);\n    padding-inline: 0 var(--space-xl);\n  }\n\n  &:focus-within {\n    background: var(--surface2);\n\n    & svg {\n      fill: white;\n    }\n\n    & picture {\n      clip-path: circle(50%);\n      background: var(--brand-bg-gradient) fixed;\n    }\n  }\n\n  & > :is(.input-stack, label) {\n    display: grid;\n    gap: var(--space-xs);\n  }\n\n  & > .input-stack > label {\n    display: contents;\n  }\n\n  & > picture {\n    block-size: var(--space-xl);\n    inline-size: var(--space-xl);\n    clip-path: circle(40%);\n    display: inline-grid;\n    place-content: center;\n    background: var(--surface3) fixed;\n\n    @media (--motionOK) {\n      transition: clip-path .3s ease;\n    }\n  }\n\n  & svg {\n    fill: var(--text2);\n    block-size: var(--space-md);\n  }\n\n  & > :is(picture, input[type=\"checkbox\"]) {\n    place-self: center;\n  }\n}\n\nsmall {\n  color: var(--text2);\n  line-height: 1.5;\n}", "demo.html": "<main>\n  <h1>Settings</h1>\n  \n  <form>\n\n    <section>\n      <header>\n        <h2>Sound & vibration</h2>\n        <small>Adjust system volume channels</small>\n      </header>\n      \n      <fieldset>\n        \n        <div class=\"fieldset-item\">\n          <picture aria-hidden=\"true\">\n            <svg viewBox=\"0 0 24 24\">\n              <title>A note icon</title>\n              <path d=\"M12 3v10.55c-.59-.34-1.27-.55-2-.55-2.21 0-4 1.79-4 4s1.79 4 4 4 4-1.79 4-4V7h4V3h-6z\"/>\n            </svg>\n          </picture>\n          <div class=\"input-stack\">\n            <label \n              for=\"media-volume\" \n              id=\"media-volume\" \n              aria-hidden=\"true\">\n                Media volume\n            </label>\n            <input \n              name=\"media-volume\" \n              aria-labelledby=\"media-volume\" \n              type=\"range\" \n              value=\"3\" \n              max=\"10\" \n              style=\"--track-fill: 30%\"\n            >\n          </div>\n        </div>\n\n        <div class=\"fieldset-item\">\n          <picture aria-hidden=\"true\">\n            <title>A phone icon</title>\n            <svg viewBox=\"0 0 24 24\">\n              <path d=\"M6.62 10.79c1.44 2.83 3.76 5.14 6.59 6.59l2.2-2.2c.27-.27.67-.36 1.02-.24 1.12.37 2.33.57 3.57.57.55 0 1 .45 1 1V20c0 .55-.45 1-1 1-9.39 0-17-7.61-17-17 0-.55.45-1 1-1h3.5c.55 0 1 .45 1 1 0 1.25.2 2.45.57 3.57.11.35.03.74-.25 1.02l-2.2 2.2z\"/>\n            </svg>\n          </picture>\n          <div class=\"input-stack\">\n            <label for=\"call-volume\" id=\"call-volume\" aria-hidden=\"true\">Call volume</label>\n            <input \n              name=\"call-volume\" \n              aria-labelledby=\"call-volume\" \n              type=\"range\" \n              value=\"7\" \n              max=\"10\" \n              style=\"--track-fill: 70%\"\n            >\n          </div>\n        </div>\n\n        <div class=\"fieldset-item\">\n          <picture aria-hidden=\"true\">\n            <svg viewBox=\"0 0 24 24\">\n              <title>A bell icon</title>\n              <path d=\"M12 22c1.1 0 2-.9 2-2h-4c0 1.1.89 2 2 2zm6-6v-5c0-3.07-1.64-5.64-4.5-6.32V4c0-.83-.67-1.5-1.5-1.5s-1.5.67-1.5 1.5v.68C7.63 5.36 6 7.92 6 11v5l-2 2v1h16v-1l-2-2z\"/>\n            </svg>\n          </picture>\n          <div class=\"input-stack\">\n            <label for=\"ring-volume\" id=\"ring-volume\" aria-hidden=\"true\">Ring volume</label>\n            <input \n              name=\"ring-volume\" \n              aria-labelledby=\"ring-volume\" \n              type=\"range\" \n              value=\"5\" \n              max=\"10\" \n              style=\"--track-fill: 50%\"\n            >\n          </div>\n        </div>\n\n        <div class=\"fieldset-item\">\n          <picture aria-hidden=\"true\">\n            <svg viewBox=\"0 0 24 24\">\n              <title>An alarm clock icon</title>\n              <path d=\"M22 5.72l-4.6-3.86-1.29 1.53 4.6 3.86L22 5.72zM7.88 3.39L6.6 1.86 2 5.71l1.29 1.53 4.59-3.85zM12.5 8H11v6l4.75 2.85.75-1.23-4-2.37V8zM12 4c-4.97 0-9 4.03-9 9s4.02 9 9 9c4.97 0 9-4.03 9-9s-4.03-9-9-9zm0 16c-3.87 0-7-3.13-7-7s3.13-7 7-7 7 3.13 7 7-3.13 7-7 7z\"/>\n            </svg>\n          </picture>\n          <div class=\"input-stack\">\n            <label for=\"alarm-volume\" id=\"alarm-volume\" aria-hidden=\"true\">Alarm volume</label>\n            <input \n              name=\"alarm-volume\" \n              aria-labelledby=\"alarm-volume\" \n              type=\"range\" \n              value=\"8\" \n              max=\"10\" \n              style=\"--track-fill: 80%\"\n            >\n          </div>\n        </div>\n        \n      </fieldset>\n    </section>\n\n    <section>\n      <header>\n        <h2>Notifications</h2>\n        <small>Turn specific channels on/off</small>\n      </header>\n      \n      <fieldset>\n\n        <div class=\"fieldset-item\">\n          <input \n            type=\"checkbox\"\n            checked\n            id=\"text-notifications\"\n            name=\"text-notifications\"\n          >\n          <div class=\"input-stack\">\n            <label for=\"text-notifications\">\n              <h3>Text Messages</h3>\n              <small>Get notified about all text messages sent to your device</small>\n            </label>\n          </div>\n        </div>\n\n        <div class=\"fieldset-item\">\n          <input \n            type=\"checkbox\"\n            id=\"voice-notifications\"\n            name=\"voice-notifications\"\n          >\n          <div class=\"input-stack\">\n            <label for=\"voice-notifications\">\n              <h3>Voice Mail</h3>\n              <small>Get notified about all voice messages sent to your device</small>\n            </label>\n          </div>\n        </div>\n\n        <div class=\"fieldset-item\">\n          <input \n            type=\"checkbox\"\n            id=\"email-notifications\"\n            name=\"email-notifications\"\n          >\n          <div class=\"input-stack\">\n            <label for=\"email-notifications\">\n              <h3>Emails</h3>\n              <small>Get notified about all text messages to your device</small>\n            </label>\n          </div>\n        </div>\n\n      </fieldset>\n    </section>\n\n  </form>\n</main>", "demo.js": "const form = document.querySelector(''form'')\nconst sliders = document.querySelectorAll(''input[type=\"range\"]'')\n\nconst rangeToPercent = slider => {\n  const max = slider.getAttribute(''max'') || 10\n  const percent = slider.value / max * 100\n\n  return `${parseInt(percent)}%`\n}\n\nsliders.forEach(slider => {\n  slider.style.setProperty(''--track-fill'', rangeToPercent(slider))\n\n  slider.addEventListener(''input'', e => {\n    e.target.style.setProperty(''--track-fill'', rangeToPercent(e.target))\n  })\n})\n\nform.addEventListener(''input'', e => {\n  const formData = Object.fromEntries(new FormData(form))\n  console.table(formData)\n})"}', '{}', '{"original_path": "patterns/components/settings"}'), ('"sidenav"', '"components"', '"vanilla"', '{"demo.css": "body {\n  display: grid;\n  grid: [stack] 1fr / min-content [stack] 1fr;\n\n  @media (max-width: 540px) {\n    & > :matches(aside, main) {\n      grid-area: stack;\n    }\n  }\n}\n\n#sidenav-open {\n  --easeOutExpo: cubic-bezier(0.16, 1, 0.3, 1);\n  --duration: .6s;\n\n  display: grid;\n  grid-template-columns: [nav] 2fr [escape] 1fr;\n\n  @media (max-width: 540px) {\n    position: sticky;\n    top: 0;\n    max-height: 100vh;\n    overflow: hidden auto;\n    overscroll-behavior: contain;\n\n    visibility: hidden; /* not keyboard accessible when closed */\n    transform: translateX(-110vw);\n    will-change: transform;\n    transition: \n      transform var(--duration) var(--easeOutExpo),\n      visibility 0s linear var(--duration);\n    \n    &:target {\n      visibility: visible;\n      transform: translateX(0);\n      transition: transform var(--duration) var(--easeOutExpo);\n    }\n  }\n\n  @media (prefers-reduced-motion: reduce) {\n    --duration: 1ms;\n  }\n}\n\n#sidenav-button,\n#sidenav-close {\n  -webkit-tap-highlight-color: transparent;\n  -webkit-touch-callout: none;\n  user-select: none;\n  touch-action: manipulation;\n\n  @media (min-width: 540px) {\n    display: none;\n  }\n}", "demo.html": "<aside id=\"sidenav-open\">\n  <nav>\n    <h4>My</h4>\n    <a href=\"#\">Dashboard</a>\n    <a href=\"#\">Profile</a>\n    <a href=\"#\">Preferences</a>\n    <a href=\"#\">Archive</a>\n\n    <h4>Settings</h4>\n    <a href=\"#\">Accessibility</a>\n    <a href=\"#\">Theme</a>\n    <a href=\"#\">Admin</a>\n  </nav>\n  \n  <a href=\"#\" id=\"sidenav-close\" title=\"Close Menu\" aria-label=\"Close Menu\" onchange=\"history.go(-1)\"></a>\n</aside>\n\n<main>\n  <header>\n    <a href=\"#sidenav-open\" id=\"sidenav-button\" class=\"hamburger\" title=\"Open Menu\" aria-label=\"Open Menu\">\n      <svg viewBox=\"0 0 50 40\" role=\"presentation\" focusable=\"false\" aria-label=\"trigram for heaven symbol\">\n        <line x1=\"0\" x2=\"100%\" y1=\"10%\" y2=\"10%\" />\n        <line x1=\"0\" x2=\"100%\" y1=\"50%\" y2=\"50%\" />\n        <line x1=\"0\" x2=\"100%\" y1=\"90%\" y2=\"90%\" />\n      </svg>\n    </a>\n    <h1>Site Title</h1>\n  </header>\n\n  <article>\n    <h2>Totam Header</h2>\n    <p>Lorem ipsum dolor, sit amet consectetur adipisicing elit. Cum consectetur, necessitatibus velit officia ut impedit veritatis temporibus soluta? Totam odit cupiditate facilis nisi sunt hic necessitatibus voluptatem nihil doloribus! Enim.</p>\n    <p>Lorem ipsum dolor sit, amet consectetur adipisicing elit. Fugit rerum, amet odio explicabo voluptas eos cum libero, ex esse quasi optio incidunt soluta eligendi labore error corrupti! Dolore, cupiditate porro.</p>\n\n    <h3>Subhead Totam Odit</h3>\n    <p>Lorem ipsum dolor sit, amet consectetur adipisicing elit. Fugit rerum, amet odio explicabo voluptas eos cum libero, ex esse quasi optio incidunt soluta eligendi labore error corrupti! Dolore, cupiditate porro.</p>\n    <p>Lorem ipsum dolor sit, amet consectetur adipisicing elit. Fugit rerum, amet odio explicabo voluptas eos cum libero, ex esse quasi optio incidunt soluta eligendi labore error corrupti! Dolore, cupiditate porro.</p>\n    \n    <h3>Subhead</h3>\n    <p>Lorem ipsum dolor sit, amet consectetur adipisicing elit. Fugit rerum, amet odio explicabo voluptas eos cum libero, ex esse quasi optio incidunt soluta eligendi labore error corrupti! Dolore, cupiditate porro.</p>\n    <p>Lorem ipsum dolor sit, amet consectetur adipisicing elit. Fugit rerum, amet odio explicabo voluptas eos cum libero, ex esse quasi optio incidunt soluta eligendi labore error corrupti! Dolore, cupiditate porro.</p>\n  </article>\n</main>", "demo.js": "const sidenav = document.querySelector(''#sidenav-open'')\nconst closenav = document.querySelector(''#sidenav-close'')\nconst opennav = document.querySelector(''#sidenav-button'')\n\n// set focus to our open/close buttons after animation\nsidenav.addEventListener(''transitionend'', e => {\n  if (e.propertyName !== ''transform'')\n    return\n\n  const isOpen = document.location.hash === ''#sidenav-open''\n\n  isOpen\n    ? closenav.focus()\n    : opennav.focus()\n\n  if (!isOpen) {\n    history.replaceState(history.state, '''')\n  }\n})\n\n// close our menu when esc is pressed\nsidenav.addEventListener(''keyup'', e => {\n  if (e.code === ''Escape'')\n    window.history.length\n      ? window.history.back()\n      : document.location.hash = ''''\n})"}', '{}', '{"original_path": "patterns/components/sidenav"}'), ('"split-buttons"', '"components"', '"vanilla"', '{"demo.css": ".gui-split-button {\n  --theme:        hsl(220 75% 50%);\n  --theme-hover:  hsl(220 75% 45%);\n  --theme-active: hsl(220 75% 40%);\n  --theme-text:   hsl(220 75% 25%);\n  --theme-border: hsl(220 50% 75%);\n  --ontheme:      hsl(220 90% 98%);\n  --popupbg:      hsl(220 0% 100%);\n\n  --border: 1px solid var(--theme-border);\n  --radius: 6px;\n  --in-speed: 500ms;\n  --out-speed: 100ms;\n\n  display: inline-flex;\n  border-radius: var(--radius);\n  background: var(--theme);\n  color: var(--ontheme);\n  fill: var(--ontheme);\n\n  touch-action: manipulation;\n  user-select: none;\n  -webkit-tap-highlight-color: transparent;\n\n  @media (--dark) {\n    --theme:        hsl(220 50% 60%);\n    --theme-hover:  hsl(220 50% 65%);\n    --theme-active: hsl(220 75% 70%);\n    --theme-text:   hsl(220 10% 85%);\n    --theme-border: hsl(220 20% 70%);\n    --ontheme:      hsl(220 90% 5%);\n    --popupbg:      hsl(220 10% 30%);\n  }\n\n  & button {\n    cursor: pointer;\n    appearance: none;\n    background: none;\n    border: none;\n\n    display: inline-flex;\n    align-items: center;\n    gap: 1ch;\n    white-space: nowrap;\n\n    font-family: inherit;\n    font-size: inherit;\n    font-weight: 500;\n\n    padding-block: 1.25ch;\n    padding-inline: 2.5ch;\n\n    color: var(--ontheme);\n    outline-color: var(--theme);\n    outline-offset: -5px;\n\n    &:is(:hover, :focus-visible) {\n      background: var(--theme-hover);\n      color: var(--ontheme);\n\n      & > svg {\n        stroke: currentColor;\n        fill: none;\n      }\n    }\n\n    &:active {\n      background: var(--theme-active);\n    }\n  }\n\n  & > button {\n    border-radius: var(--radius) 0 0 var(--radius);\n\n    @supports (border-start-start-radius: 1px) {\n      border-end-start-radius: var(--radius);\n      border-start-start-radius: var(--radius);\n    }\n  }\n\n  @media (--light) {\n    & > button,\n    & button:is(:focus-visible, :hover) {\n      text-shadow: 0 1px 0 var(--theme-active);\n    }\n    & > .gui-popup-button > svg,\n    & button:is(:focus-visible, :hover) > svg {\n      filter: drop-shadow(0 1px 0 var(--theme-active));\n    }\n  }\n  \n  & svg {\n    inline-size: 2ch;\n    box-sizing: content-box;\n    stroke-linecap: round;\n    stroke-linejoin: round;\n    stroke-width: 2px;\n  }\n}\n\n.gui-popup-button {\n  inline-size: 4ch;\n  cursor: pointer;\n  position: relative;\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  border-inline-start: var(--border);\n  border-radius: 0 var(--radius) var(--radius) 0;\n\n  @supports (border-start-start-radius: 1px) {\n    border-inline-start: var(--border);\n    border-start-end-radius: var(--radius);\n    border-end-end-radius: var(--radius);\n  }\n\n  &:is(:hover,:focus-within) {\n    background: var(--theme-hover);\n  }\n\n  /* fixes iOS trying to be helpful */\n  &:focus {\n    outline: none;\n  }\n\n  &:active {\n    background: var(--theme-active);\n  }\n  \n  &:focus-within {\n    & > svg {\n      transition-duration: var(--in-speed);\n      transform: rotateZ(.5turn);\n    }\n    & > .gui-popup {\n      transition-duration: var(--in-speed);\n      opacity: 1;\n      transform: translateY(0);\n      pointer-events: auto;\n    }\n  }\n\n  @media (--motionOK) {\n    & > svg {\n      transition: transform var(--out-speed) ease;\n    }\n    & > .gui-popup {\n      transform: translateY(5px);\n\n      transition: \n        opacity var(--out-speed) ease,\n        transform var(--out-speed) ease;\n    }\n  }\n}\n\n.gui-popup {\n  --shadow: 220 70% 15%;\n  --shadow-strength: 1%;\n\n  opacity: 0;\n  pointer-events: none;\n\n  position: absolute;\n  inset-block-end: 80%;\n  inset-inline-start: -1.5ch;\n  \n  list-style-type: none;\n  background: var(--popupbg);\n  color: var(--theme-text);\n  padding-inline: 0;\n  padding-block: .5ch;\n  border-radius: var(--radius);\n  overflow: hidden;\n  display: flex;\n  flex-direction: column;\n  font-size: .9em;\n  transition: opacity var(--out-speed) ease;\n\n  box-shadow:\n    0 -2px 5px 0 hsl(var(--shadow) / calc(var(--shadow-strength) + 5%)),\n    0 1px 1px -2px hsl(var(--shadow) / calc(var(--shadow-strength) + 10%)),\n    0 2px 2px -2px hsl(var(--shadow) / calc(var(--shadow-strength) + 12%)),\n    0 5px 5px -2px hsl(var(--shadow) / calc(var(--shadow-strength) + 13%)),\n    0 9px 9px -2px hsl(var(--shadow) / calc(var(--shadow-strength) + 14%)),\n    0 16px 16px -2px hsl(var(--shadow) / calc(var(--shadow-strength) + 20%))\n  ;\n\n  /* fixes iOS trying to be helpful */\n  &:focus {outline: none}\n\n  @media (--dark) {\n    --shadow-strength: 5%;\n    --shadow: 220 3% 2%;\n\n    & button:not(:focus-visible, :hover) {\n      text-shadow: 0 1px 0 var(--ontheme);\n    }\n\n    & button:not(:focus-visible, :hover) > svg {\n      filter: drop-shadow(0 1px 0 var(--ontheme));\n    }\n  }\n\n  @media (width <= 400px) {\n    inset-inline-start: -200%;\n  }\n\n  & svg {\n    fill: var(--popupbg);\n    stroke: var(--theme);\n\n    @media (prefers-color-scheme: dark) {\n      stroke: var(--theme-border);\n    }\n  }\n\n  & button {\n    color: var(--theme-text);\n    width: 100%;\n  }\n}", "demo.html": "<div class=\"gui-split-button\">\n  <button>View Cart</button>\n  <span class=\"gui-popup-button\" aria-haspopup=\"true\" aria-expanded=\"false\" title=\"Open for more actions\">\n    <svg aria-hidden=\"true\" viewBox=\"0 0 20 20\">\n      <path d=\"M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z\" />\n    </svg>\n    <ul class=\"gui-popup\">\n      <li><button>\n        <svg aria-hidden=\"true\" viewBox=\"0 0 24 24\">\n          <path d=\"M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z\" />\n        </svg>\n        Checkout\n      </button></li>\n      <li><button>\n        <svg aria-hidden=\"true\" viewBox=\"0 0 24 24\">\n          <path d=\"M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z\" />\n        </svg>\n        Quick Pay\n      </button></li>\n      <li><button>\n        <svg aria-hidden=\"true\" viewBox=\"0 0 24 24\">\n          <path d=\"M5 5a2 2 0 012-2h10a2 2 0 012 2v16l-7-3.5L5 21V5z\" />\n        </svg>\n        Save for later\n      </button></li>\n    </ul>\n  </span>\n</div>\n\n<div class=\"gui-split-button\">\n  <button>Send</button>\n  <span class=\"gui-popup-button\" aria-haspopup=\"true\" aria-expanded=\"false\" title=\"Open for more actions\">\n    <svg aria-hidden=\"true\" viewBox=\"0 0 20 20\">\n      <path d=\"M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z\" />\n    </svg>\n    <ul class=\"gui-popup\">\n      <li><button>\n        <svg aria-hidden=\"true\" viewBox=\"0 0 24 24\">\n          <path d=\"M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z\" />\n        </svg>\n        Schedule for later\n      </button></li>\n      <li><button>\n        <svg aria-hidden=\"true\" viewBox=\"0 0 24 24\">\n          <path d=\"M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16\" />\n        </svg>\n        Delete\n      </button></li>\n      <li><button>\n        <svg aria-hidden=\"true\" viewBox=\"0 0 24 24\">\n          <path d=\"M5 5a2 2 0 012-2h10a2 2 0 012 2v16l-7-3.5L5 21V5z\" />\n        </svg>\n        Save draft\n      </button></li>\n    </ul>\n  </span>\n</div>\n\n<div class=\"gui-split-button\">\n  <button>Squash</button>\n  <span class=\"gui-popup-button\" aria-haspopup=\"true\" aria-expanded=\"false\" title=\"Open for more actions\">\n    <svg aria-hidden=\"true\" viewBox=\"0 0 20 20\">\n      <path d=\"M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z\" />\n    </svg>\n    <ul class=\"gui-popup\">\n      <li><button>\n        Create a merge commit\n      </button></li>\n      <li><button>\n        Rebase\n      </button></li>\n    </ul>\n  </span>\n</div>", "demo.js": "import $ from ''blingblingjs''\nimport {rovingIndex} from ''roving-ux''\n\nconst splitButtons = $(''.gui-split-button'')\nconst popupButtons = $(''.gui-popup-button'')\n\n// popup activating roving index for it''s buttons\npopupButtons.forEach(element => \n  rovingIndex({\n    element,\n    target: ''button'',\n  }))\n\n// support escape key\npopupButtons.on(''keyup'', e => {\n  if (e.code === ''Escape'')\n    e.target.blur()\n})\n\npopupButtons.on(''focusin'', e => {\n  e.currentTarget.setAttribute(''aria-expanded'', true)\n})\n\npopupButtons.on(''focusout'', e => {\n  e.currentTarget.setAttribute(''aria-expanded'', false)\n})\n\n// respond to any button interaction\nsplitButtons.on(''click'', event => {\n  if (event.target.nodeName !== ''BUTTON'') return\n  console.info(event.target.innerText)\n})"}', '{}', '{"original_path": "patterns/components/split-buttons"}');